//# sourceMappingURL=data:application/json;charset=utf-8;base64,{"version":3,"file":"index.js","sources":["src/js/admin/queries/list.js","src/js/admin/queries/detail.js","src/js/admin/queries/edit.js","src/js/admin/charts.js","src/js/admin/queries/results.js","src/js/admin/queries/share.js","src/js/admin/queries/api.js","src/js/admin/queries/manager.js","src/js/admin/engine.js"],"sourcesContent":["class QueryListManager {\n  constructor ({manager = null}) {\n    this.manager = manager\n    this.data = []\n    this._click_query_detail = this._click_query_detail.bind(this)\n    this._click_query_create = this._click_query_create.bind(this)\n    this._click_status_dropdown = this._click_status_dropdown.bind(this)\n    this._click_status_filter = this._click_status_filter.bind(this)\n    this._change_search_input = this._change_search_input.bind(this)\n    this.filters = {\n      search: null,\n      status: null,\n    }\n    this.comps = {\n      status: {\n        button: document.querySelector(\"#query-list .status-filter-button\"),\n        content: document.querySelector(\"#query-list .status-filter-dropdown\"),\n        items: document.querySelectorAll(\"#query-list .status-filter .dropdown-item\"),\n      },\n      search: document.querySelector(\"#query-list #query-list-search-input\"),\n      query_list: document.querySelector(\"#query-list .query-item-list\"),\n      query_template: document.querySelector(\"#query-item-template\"),\n      query_create: {\n        content: document.querySelector(\"#query-list-empty-content\"),\n        action: document.querySelector(\"#query-list-create-query\"),\n      }\n    }\n    this.comps.status.button.addEventListener(\n      \"click\", this._click_status_dropdown, false\n    )\n    for (let item of this.comps.status.items) {\n      item.addEventListener(\"click\", this._click_status_filter, false)\n    }\n    this.comps.search.addEventListener(\"input\", this._change_search_input, false)\n    this.comps.query_create.action.addEventListener(\"click\", this._click_query_create, false)\n  }\n\n  show_view(on_history) {\n    fetch (this.manager.url_base, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.data = data.list\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-list\", null)\n          }\n        })\n      } else {\n        console.log(response)\n      }\n    })\n  }\n\n  _set_in_view() {\n    if (this.data.length > 0) {\n      this.comps.query_create.content.classList.add(\"hidden\")\n      this._set_query_list()\n    } else {\n      this.comps.query_list.innerHTML = \"\"\n      this.comps.query_create.content.classList.remove(\"hidden\")\n    }\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_list.classList.remove(\"hidden\")\n  }\n\n  _set_query_list() {\n    this.comps.query_list.innerHTML = \"\"\n    let template = this.comps.query_template.cloneNode(true)\n    template.classList.remove(\"hidden\")\n    for (let item of this.data) {\n      if (this._is_query_in_the_filter(item)) {\n        let query_item = template.cloneNode(true)\n        let returned_query_item = this.manager._create_query_item(item, query_item)\n        let detail_link = returned_query_item.querySelector(\".secondary-button.item-detail-link\")\n        detail_link.query_uuid = item.uuid\n        detail_link.addEventListener(\n          \"click\", this._click_query_detail, false\n        )\n        if (this.manager.engine.user.is_superuser && item.created_by_email) {\n          let email = document.createElement(\"div\")\n          email.classList.add(\"query-item-created-by\")\n          email.textContent = item.created_by_email\n          returned_query_item.appendChild(email)\n        }\n        this.comps.query_list.appendChild(returned_query_item)\n      }\n    }\n  }\n\n  _is_query_in_the_filter(query) {\n    if (!this.filters.search && !this.filters.status) {\n      return true\n    }\n    let lower_search = typeof this.filters.search === \"string\" ? this.filters.search.toLowerCase() : null\n    let search_in_name = lower_search ? query.name.toLowerCase().includes(lower_search): true\n    let equal_status = this.filters.status ? query.status_verbose.code === this.filters.status: true\n    return search_in_name && equal_status\n  }\n\n  _click_query_detail (event) {\n    this.manager.engine.cursor.key = event.currentTarget.query_uuid\n    this.manager.engine.show_view(\"query-detail\", true)\n  }\n\n  _click_query_create (event) {\n    this.manager.engine.show_view(\"query-create\", true)\n  }\n\n  _click_status_dropdown (event) {\n    if (this.comps.status.content.classList.contains(\"hidden\")) {\n      this.comps.status.content.classList.remove(\"hidden\")\n    } else {\n      this.comps.status.content.classList.add(\"hidden\")\n    }\n  }\n\n  _click_status_filter (event) {\n    for (let item of this.comps.status.items) {\n      item.classList.remove(\"active\")\n    }\n    event.target.classList.add(\"active\")\n    let status_code = event.target.getAttribute(\"code\")\n    if (status_code) {\n      this.comps.status.button.querySelector(\".current\").textContent = event.target.textContent\n      this.filters.status = status_code\n    } else {\n      this.comps.status.button.querySelector(\".current\").textContent = \"Filtrar\"\n      this.filters.status = null\n    }\n    this._set_query_list()\n    this.comps.status.content.classList.add(\"hidden\")\n  }\n\n  _change_search_input (event) {\n    let value = typeof event.target.value === \"string\" ? event.target.value.trim(): null\n    value = value !== \"\"? value : null\n    event.target.value = value\n    this.filters.search = value\n    this._set_query_list()\n  }\n\n}\n\nexport {QueryListManager}\n","class QueryDetailManager {\n  constructor ({manager = null}) {\n    this.manager = manager\n    this.data = {}\n    this.charts = {\n      summary: null\n    }\n    this.map_pointers = []\n    this._click_query_edit = this._click_query_edit.bind(this)\n  }\n\n  show_view(on_history) {\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.data = data\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-detail\", data.query.url_code)\n          }\n        })\n      } else {\n        console.log(response)\n        this.manager.engine.show_view(\"query-list\", false)\n      }\n    })\n  }\n\n  _set_in_view () {\n    let query_item = document.querySelector(\"#query-detail-item\")\n    let returned_query_item = this.manager._create_query_item(this.data.query, query_item)\n    if (this.data.query.is_active || this.data.query.is_earring) {\n      document.querySelector(\"#detail-action-submit\").setAttribute(\"href\", this.data.links.submit)\n      document.querySelector(\"#detail-action-submit\").classList.remove(\"hidden\")\n    } else {\n      document.querySelector(\"#detail-action-submit\").classList.add(\"hidden\")\n    }\n    this._set_query_preview()\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_detail.classList.remove(\"hidden\")\n  }\n\n  _click_query_edit (event) {\n    this.manager.engine.show_view(\"query-update\", true)\n  }\n\n  _set_query_preview () {\n    let description_element = document.querySelector(\"#query-detail .query-preview-description\")\n    if (this.data.query.description) {\n      description_element.textContent = this.data.query.description\n    } else {\n      description_element.textContent = \"*Sin descripción configurada\"\n    }\n    let questions = document.querySelector(\"#query-detail .query-preview-questions\")\n    questions.innerHTML = \"\"\n    for (let i in this.map_pointers) {\n      this.map_pointers[i].remove()\n    }\n    this.map_pointers = []\n    let index = 0\n    for (let answer_result of this.data.answer_results) {\n      let question = answer_result.question\n      let question_container = document.createElement(\"div\")\n      question_container.classList.add(\"question-container\")\n      question_container.innerHTML = `\n        <div class=\"subtitle\">Pregunta ${index + 1}</div>\n        <div class=\"question-item-kind\">${this.manager.get_kind_label(question)}</div>\n        <div class=\"question-name\">${question.name}</div>\n        <div class=\"question-description\">${question.description? question.description: \"\"}</div>\n      `\n      if (question.image) {\n        question_container.innerHTML += `<div class=\"question-item-image-preview-content\"><img class=\"question-item-image-preview\" src=\"${question.image}\"></div>`\n      }\n      // here\n      if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question.kind)) {\n        question_container.innerHTML += `<div class=\"question-options\"></div>`\n        let options_container = question_container.querySelector(\".question-options\")\n        let option_index = 0\n        for (let option of question.options) {\n          let inner_html = \"\"\n          if (question.kind === \"SELECT\") {\n            inner_html = `\n              <div class=\"option\">\n                <span class=\"option-label\">${this.manager.letters[option_index]}.</span>\n                <span class=\"option-value\">${option.name}</span>\n              </div>\n            `\n          } else {\n            inner_html = `\n              <div class=\"option-image\">\n                <div class=\"option-image-index\">${option_index + 1}.</div>\n                <div class=\"option-image-content\">\n                  <img class=\"option-image-img\" src=\"${option.image}\">\n                  <div class=\"option-image-label\">${option.name}</div>\n                </div>\n              </div>\n            `\n          }\n          options_container.innerHTML += inner_html\n          option_index += 1\n        }\n      } else {\n        question_container.innerHTML += this.manager._get_question_kind_html(question)\n      }\n      questions.appendChild(question_container)\n      if (question.kind === \"POINT\") {\n        if (question.default_point == null) {\n          question.default_point = {latitude: -33.447869, longitude: -70.668423}\n        }\n        let latitude = question.default_point.latitude? question.default_point.latitude: -33.447869\n        let longitude = question.default_point.longitude? question.default_point.longitude: -70.668423\n        let zoom = question.default_zoom? question.default_zoom: 9\n        let latlng = L.latLng(latitude, longitude)\n        let map = L.map(`map-pointer-${question.uuid}`).setView(latlng, zoom)\n        L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {\n          maxZoom: 19,\n          zoomControl: false,\n        }).addTo(map);\n        map.attributionControl.setPrefix(\"\")\n        map.zoomControl.remove()\n        map.dragging.disable()\n        map.doubleClickZoom.disable()\n        map.scrollWheelZoom.disable()\n        setTimeout(function () {\n          window.dispatchEvent(new Event('resize'));\n        }, 100);\n        this.map_pointers.push(map)\n      }\n      index += 1\n    }\n  }\n}\n\nexport {QueryDetailManager}\n","class QueryEditBase {\n  constructor ({manager = null}) {\n    this.manager = manager\n    this.required_fields = [\"name\"]\n    this.data = this._get_default_data()\n    this.question_images = {}\n    this.question_option_images = []\n    this.inputs = {}\n    this.errors = {}\n    this.buttons = {}\n    this.can_edit_questions = true\n    this.map_pointers = []\n\n    this._click_publish = this._click_publish.bind(this)\n    this._dropdown_create_question = this._dropdown_create_question.bind(this)\n    this._click_create_question = this._click_create_question.bind(this)\n    this._move_question_ondragstart = this._move_question_ondragstart.bind(this)\n    this._move_question_ondragend = this._move_question_ondragend.bind(this)\n    this._move_question_ondrop = this._move_question_ondrop.bind(this)\n    this._click_remove_question = this._click_remove_question.bind(this)\n    this._change_input = this._change_input.bind(this)\n    this._click_question_add_option = this._click_question_add_option.bind(this)\n    this._click_question_max_answers_menu = this._click_question_max_answers_menu.bind(this)\n    this._click_question_max_answers_set = this._click_question_max_answers_set.bind(this)\n    this._click_question_remove_option = this._click_question_remove_option.bind(this)\n    this._click_question_image_modal = this._click_question_image_modal.bind(this)\n    this._click_question_image_rm = this._click_question_image_rm.bind(this)\n    this._click_question_option_image = this._click_question_option_image.bind(this)\n    this._change_map_pointer = this._change_map_pointer.bind(this)\n\n    this._change_input_question_image = this._change_input_question_image.bind(this)\n    this._set_initial()\n    this._set_publish_button()\n    this._set_create_question_button()\n    this._set_query_inputs()\n  }\n\n  _get_default_data () {\n    return {\n        name: null,\n        description: null,\n        start_at: null,\n        end_at: null,\n        active: true,\n        questions: [],\n        auth_rut: \"OPTIONAL\",\n        auth_email: \"OPTIONAL\",\n    }\n  }\n\n  _set_initial() {}\n\n  _set_publish_button () {\n    let publish = document.querySelector(`#${this.view_type}-query-button`)\n    publish.disabled = true\n    publish.classList.add(\"disabled\")\n    publish.addEventListener(\"click\", this._click_publish, false)\n    this.buttons.publish = publish\n  }\n\n  _click_publish(event) {\n    let publish = document.querySelector(`#${this.view_type}-query-button`)\n    if (publish.disabled == false) {\n      this.manager.engine._set_loading()\n      this.execute_service()\n    }\n  }\n\n  execute_service () {}\n\n  _clean_data() {\n    this.data = this._get_default_data()\n    this.question_images = {}\n    this._remove_all_question_option_image()\n    this._build_question_from_data()\n    for (let field in this.inputs) {\n      let input = this.inputs[field]\n      if ([\"start_at\", \"end_at\"].includes(field) && this.data[field]) {\n        input.value = new Date(this.data[field]).toISOString().split('T')[0]\n      } else {\n        input.value = this.data[field]\n      }\n      if ([\"name\"].includes(field)) {\n        input.parentNode.dataset.replicatedValue = this.data[field]\n      }\n    }\n    this.validate_inputs()\n  }\n\n  _set_query_inputs() {\n    let name = document.querySelector(`#query-${this.view_type}-name`)\n    let description = document.querySelector(`#query-${this.view_type}-description`)\n    let start_at = document.querySelector(`#query-${this.view_type}-start_at`)\n    let end_at = document.querySelector(`#query-${this.view_type}-end_at`)\n    let active = document.querySelector(`#query-${this.view_type}-active`)\n    let auth_email = document.querySelector(`#query-${this.view_type}-auth-email`)\n    let auth_rut = document.querySelector(`#query-${this.view_type}-auth-rut`)\n    for (let input of [name, description, start_at, end_at, active, auth_email, auth_rut]) {\n      input.field = input.getAttribute(\"field\")\n      input.addEventListener(\"input\", this._change_input, false)\n      this.inputs[input.field] = input\n    }\n    this.error_containers = {}\n    for (let field in this.data) {\n      if (field != \"questions\") {\n        let container = document.querySelector(`#query-${this.view_type}-${field}-error`)\n        if (container) {\n          this.error_containers[field] = container\n        }\n      }\n    }\n    this.error_containers[\"times\"] = document.querySelector(`#query-${this.view_type}-times-error`)\n  }\n\n  _set_errors_message() {\n    for (let field in this.error_containers) {\n      if (field != \"questions\") {\n        this.error_containers[field].innerText = \"\"\n      } else {\n        for (let index in this.error_containers[field]) {\n          for (let question_field in this.error_containers[field][index]) {\n            this.error_containers[field][index][question_field].innerText = \"\"\n          }\n        }\n      }\n    }\n    for (let field in this.errors) {\n      if (![\"questions\", \"start_at\", \"end_at\"].includes(field)) {\n        this.error_containers[field].innerText = this.errors[field]\n      } else if ([\"start_at\", \"end_at\"].includes(field)) {\n        this.error_containers.times.innerText = this.errors[field]\n      } else if (typeof this.errors[field] == \"object\") {\n        for (let index in this.errors[field]) {\n          for (let question_field in this.errors[field][index]) {\n            this.error_containers[field][parseInt(index)][question_field].innerText = this.errors[field][index][question_field]\n          }\n        }\n      }\n    }\n  }\n\n  _change_input (event) {\n    let field = event.target.field\n    let value = event.target.value != \"\"? event.target.value: null\n    if (event.target.question) {\n      if (field == \"required\") {\n        value = event.target.checked? true: false\n      }\n      if (field == \"question-option\") {\n        this.data.questions[event.target.index].options[event.target.option_index].name = value\n      } else {\n        this.data.questions[event.target.index][field] = value\n      }\n    } else {\n      this.data[field] = value\n    }\n    if (event.target.parentNode.classList.contains(\"textarea-wrap\")) {\n      event.target.parentNode.dataset.replicatedValue = value\n    }\n    this.validate_inputs()\n    this._set_errors_message()\n  }\n\n  validate_inputs() {\n    this.errors = {}\n    let no_question_message = \"Debe crear al menos una pregunta\"\n    if (this.data.questions.length == 0) {\n      this.errors.questions = no_question_message\n    } else {\n      delete this.errors.questions\n    }\n    for (let field in this.data) {\n      if (field == \"questions\") {\n        for (let question of this.data.questions) {\n          for (let field in question) {\n            let value = question[field]\n            this._val_field_value_is_required(field, value, question.order)\n          }\n          if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question.kind)) {\n            this._val_question_options(question)\n          }\n        }\n      } else {\n        let value = this.data[field]\n        this._val_field_value_is_required(field, value)\n        if (value && [\"start_at\", \"end_at\"].includes(field)) {\n          this._val_date_field_value(field, value)\n        }\n      }\n    }\n    if (this.errors.questions && this.errors.questions.length == 0) {\n      delete this.errors.questions\n    }\n    if (this.errors.questions && this.errors.questions != no_question_message) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n    } else {\n      this.buttons.new_question.disabled = false\n      this.buttons.new_question.classList.remove(\"disabled\")\n    }\n    if (this.data.questions.length >= 60) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n      let max_question_message = document.createElement(\"div\")\n      max_question_message.classList.add(\"end-max-question-message\")\n      max_question_message.innerText = \"Has superado el número máximo de preguntas para este formulario.\"\n      document.querySelector(`#query-components-${this.view_type}`).appendChild(max_question_message)\n    } else {\n      let max_question_message = document.querySelector(`#query-components-${this.view_type} .end-max-question-message`)\n      if (max_question_message != null) {\n        max_question_message.remove()\n      }\n    }\n    if (!this.can_edit_questions) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n    }\n    if (\n      Object.keys(this.errors).length === 0\n      && this.errors.constructor === Object\n    ) {\n      this.buttons.publish.classList.remove(\"disabled\")\n      this.buttons.publish.disabled = false\n    } else {\n      this.buttons.publish.classList.add(\"disabled\")\n      this.buttons.publish.disabled = true\n    }\n  }\n\n  _val_date_field_value(field, value) {\n    let start_at = this.data[\"start_at\"]? new Date(this.data[\"start_at\"]): null\n    let end_at = this.data[\"end_at\"]? new Date(this.data[\"end_at\"]): null\n    if (start_at && end_at && start_at >= end_at) {\n      let message = \"La fecha de inicio debe ser menor que la de término\"\n      this._set_field_error(field, message)\n    } else {\n      this._clean_field_error(\"start_at\")\n    }\n  }\n\n  _val_field_value_is_required(field, value, question_index) {\n    if (this.required_fields.includes(field) && (!value || value.trim() == \"\")) {\n      let message = \"Este campo es requerido\"\n      this._set_field_error(field, message, question_index)\n    } else {\n      this._clean_field_error(field, question_index)\n    }\n  }\n\n  _val_question_options(question) {\n    let message = \"Debe agregar al menos dos opciones y no pueden estar vacías\"\n    if (question.options.length < 2) {\n      this._set_field_error(\"options\", message, question.order)\n    }\n    let option_values = []\n    for (let option of question.options) {\n      if (!option.name || option.name.trim() == \"\") {\n        this._set_field_error(\"options\", message, question.order)\n        break\n      }\n      if (option_values.includes(option.name)) {\n        message = \"Las opciones no pueden ser iguales\"\n        this._set_field_error(\"options\", message, question.order)\n        break\n      }\n      option_values.push(option.name)\n    }\n  }\n\n  _set_field_error (field, message, question_index) {\n    if (!isNaN(question_index)) {\n      if (!this.errors.questions) {\n        this.errors.questions = {}\n      }\n      if (!this.errors.questions[question_index]) {\n        this.errors.questions[question_index] = {}\n      }\n      this.errors.questions[question_index][field] = message\n    } else {\n      this.errors[field] = message\n    }\n  }\n\n  _clean_field_error (field, question_index) {\n    if (!isNaN(question_index) && this.errors.questions && this.errors.questions[question_index]) {\n      delete this.errors.questions[question_index][field]\n    }\n    if (isNaN(question_index)) {\n      delete this.errors[field]\n    }\n  }\n\n  _set_create_question_button() {\n    let button = document.querySelector(`#query-${this.view_type}-create-question-button`)\n    button.addEventListener(\"click\", this._dropdown_create_question, false)\n    button.disabled = false\n    this.buttons.new_question = button\n    let kinds = Array.from(document.querySelectorAll(`#query-${this.view_type}-create-question-kinds .dropdown-item`))\n    for (let kind of kinds) {\n      kind.kind = kind.getAttribute(\"kind\")\n      kind.type = kind.getAttribute(\"type\")\n      kind.addEventListener(\"click\", this._click_create_question, false)\n    }\n  }\n\n  _dropdown_create_question(event) {\n    let button = document.querySelector(`#query-${this.view_type}-create-question-button`)\n    if (this.can_edit_questions) {\n      let dropdown = document.querySelector(`#query-${this.view_type}-create-question-kinds`)\n      if (!button.disabled) {\n        if (dropdown.classList.contains(\"hidden\")) {\n          dropdown.classList.remove(\"hidden\")\n        } else {\n          dropdown.classList.add(\"hidden\")\n        }\n      }\n    }\n  }\n\n  _click_create_question (event) {\n    let question = {\n      kind: event.target.kind,\n      name: null, description: null,\n      required: false,\n      order: this.data.questions.length,\n    }\n    if (event.target.kind === \"TEXT\") {\n      if (event.target.type == \"large\") {\n        question.text_max_length = 400\n      } else {\n        question.text_max_length = 150\n      }\n    } else if ([\"SELECT\", \"SELECT_IMAGE\"].includes(event.target.kind)) {\n      question.options = []\n    } else if (event.target.kind === \"POINT\") {\n      question.default_point = {\n        latitude: -33.447869, longitude: -70.668423\n      }\n      question.default_zoom = 9\n    }\n    this.data.questions.push(question)\n    this._build_question_from_data()\n    let dropdown = document.querySelector(`#query-${this.view_type}-create-question-kinds`)\n    dropdown.classList.add(\"hidden\")\n    document.querySelector(`#query-${this.view_type}-questions-tab .question-item:last-child`).scrollIntoView()\n  }\n\n  _build_question_from_data() {\n    let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`)\n    questions_container.innerHTML = \"\"\n    for (let i in this.map_pointers) {\n      this.map_pointers[i].remove()\n    }\n    this.map_pointers = []\n    let index = 0\n    for (let question_data of this.data.questions) {\n      let question = this._create_question_element(question_data, index)\n      this._set_question_image(question, question_data)\n      questions_container.appendChild(question)\n      let delete_button = question.querySelector(\".action-delete\")\n      this._prepare_question_inputs(question, question_data, [\"name\", \"description\", \"required\"])\n      if (question_data.kind === \"POINT\") {\n        this._set_map_pointer(question, question_data)\n      }\n      if (this.can_edit_questions) {\n        let click_delete = this._get_question_delete_callback()\n        delete_button.addEventListener(\"click\", click_delete, false)\n        this._set_question_draggable(question)\n        this._set_question_error_containers(question)\n      } else {\n        delete_button.remove()\n        this._set_disable_edit_questions(question)\n      }\n      index += 1\n    }\n    this.validate_inputs()\n  }\n\n  _set_map_pointer(question, question_data) {\n    let latitude = question_data.default_point.latitude? question_data.default_point.latitude: -33.447869\n    let longitude = question_data.default_point.longitude? question_data.default_point.longitude: -70.668423\n    let zoom = question_data.default_zoom? question_data.default_zoom: 9\n    let latlng = L.latLng(latitude, longitude)\n    let map = L.map(`map-pointer-question-edit-${question.index}`).setView(latlng, zoom)\n    L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {\n      maxZoom: 19,\n    }).addTo(map);\n    map.attributionControl.setPrefix(\"\")\n    map.question_index = question.index\n    map.addEventListener(\"moveend\", this._change_map_pointer, false)\n    map.zoomControl.setPosition(\"bottomright\")\n    setTimeout(function () {\n      window.dispatchEvent(new Event('resize'));\n    }, 100);\n    this.map_pointers.push(map)\n  }\n\n  _change_map_pointer(event) {\n    let question_index = event.target.question_index\n    let center = event.target.getCenter()\n    this.data.questions[question_index].default_point = {\n      latitude: center.lat, longitude: center.lng\n    }\n    this.data.questions[question_index].default_zoom = event.target.getZoom()\n  }\n\n  _get_question_delete_callback() {\n    return this._click_remove_question\n  }\n\n  _get_question_id(index) { return `query-${this.view_type}-question-item-${index}` }\n\n  _create_question_element(question_data, index) {\n    let question_id = this._get_question_id(index)\n    var question = document.createElement(\"div\")\n    question.classList.add(\"question-item\")\n    question.index = index\n    question.setAttribute(\"id\", question_id)\n    question.kind = question_data.kind\n    let kind_label = this.manager.get_kind_label(question_data)\n    question.innerHTML = `\n      <div class=\"question-move-previous\"></div>\n      <div class=\"question-container\">\n        <div class=\"question-item-move\">\n          <i class=\"icon move\"></i>\n        </div>\n        <div class=\"question-item-content\">\n          <div class=\"question-item-kind\">${kind_label}</div>\n          <div class=\"textarea-wrap question-item-name\">\n            <textarea class=\"question-item-name\"\n                   id=\"query-${this.view_type}-${question_id}-name-input\"\n                   field=\"name\"\n                   rows=\"1\"\n                   placeholder=\"Escribe tu pregunta aquí\">\n            </textarea>\n          </div>\n          <div class=\"error-label\" id=\"query-${this.view_type}-question-${index}-name-error\"></div>\n          <div class=\"textarea-wrap question-item-description\">\n            <textarea class=\"question-item-description\"\n                   id=\"query-${this.view_type}-${question_id}-description-input\"\n                   field=\"description\"\n                   rows=\"1\"\n                   placeholder=\"Agrega una descripción para esta pregunta (opcional)\">\n            </textarea>\n          </div>\n          <div class=\"error-label\" id=\"query-${this.view_type}-question-${index}-description-error\"></div>\n          <div class=\"question-item-image-preview-content hidden\">\n            <img class=\"question-item-image-preview\"><div class=\"icon close\" id=\"question-item-image-preview-${index}-rm\"></div>\n          </div>\n        </div>\n        <div class=\"question-item-actions\">\n          <div class=\"actions-top\">\n            <div class=\"action-delete\"><i class=\"icon close-dark\"></i></div>\n          </div>\n          <div class=\"actions-bottom\">\n            <div class=\"action-required\">\n              <label class=\"action-checkbox\">\n                <div class=\"action-label\">Obligatorio</div>\n                <input type=\"checkbox\"\n                       id=\"query-${this.view_type}-${question_id}-required-input\"\n                       field=\"required\"\n                       class=\"action-checkbox-input\">\n                </input>\n                <span class=\"action-checkbox-checkmarker\"></span>\n              </label>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"question-move-next\"></div>\n    `\n    let question_content = question.querySelector(\".question-item-content\")\n    if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question_data.kind)) {\n      this._set_question_options(question, question_data)\n      this._set_question_max_answers(question, question_data)\n    } else if (question_data.kind === \"POINT\") {\n      question_content.innerHTML += `<div class=\"query-map-pointer\" id=\"map-pointer-question-edit-${index}\"></div>`\n      question_content.querySelector(\".query-map-pointer\").draggable = true\n    } else {\n      question_content.innerHTML += this.manager._get_question_kind_html(question_data)\n    }\n    return question\n  }\n\n  _set_question_image(question, question_data) {\n    let actions = question.querySelector(\".question-item-actions .actions-bottom\")\n    let action_image = document.createElement(\"div\")\n    action_image.classList.add(\"action-question-image\", \"icon\", \"image\")\n    action_image.setAttribute(\"id\", `action-question-image-${question.index}`)\n    action_image.question_index = question.index\n    let question_image_input = document.createElement(\"input\")\n    question_image_input.setAttribute(\"id\", `action-question-image-${question.index}-input`)\n    question_image_input.setAttribute(\"type\", \"file\")\n    question_image_input.classList.add(\"hidden\")\n    actions.insertBefore(action_image, actions.firstChild)\n    actions.appendChild(question_image_input)\n    action_image.addEventListener(\"click\", this._click_question_image_modal, false)\n\n    let image_preview = question.querySelector(\".question-item-image-preview\")\n    let image_preview_content = question.querySelector(\".question-item-image-preview-content\")\n    if (this.question_images[question.index] && this.question_images[question.index].url) {\n      image_preview.setAttribute(\"src\", this.question_images[question.index].url)\n      image_preview_content.classList.remove(\"hidden\")\n    } else if (question_data.image){\n      image_preview.setAttribute(\"src\", question_data.image)\n      image_preview_content.classList.remove(\"hidden\")\n    }\n    let rm_button = question.querySelector(`#question-item-image-preview-${question.index}-rm`)\n    rm_button.question_index = question.index\n    rm_button.addEventListener(\"click\", this._click_question_image_rm, false)\n  }\n\n  _click_question_image_modal(event) {\n    let html_element = document.createElement(\"div\")\n    html_element.innerHTML = `\n      <div class=\"question-image-upload-content\">\n        <div class=\"question-image-button\">\n          <label for=\"question-image-upload-input\"><div class=\"primary-button\">Adjuntar imagen</div></label>\n          <input type=\"file\" accept=\"image/*\" maxlength=\"1\" class=\"hidden\" id=\"question-image-upload-input\">\n        </div>\n      </div>\n    `\n    let config = {\n      class: \"query-question-upload-image\",\n      html_element: html_element,\n    }\n    let image_input = html_element.querySelector(\"#question-image-upload-input\")\n    image_input.question_index = event.target.question_index\n    image_input.addEventListener(\n      \"input\", this._change_input_question_image, false\n    )\n    this.manager.engine.show_modal(config)\n  }\n\n  _click_question_image_rm (event) {\n    let question_index = event.target.question_index\n    let question = this.data.questions[question_index]\n    if (question.image) {\n      this.question_images[question_index] = {\n        question_uuid: question.uuid,\n        file: null,\n      }\n    } else if (this.question_images[question_index]) {\n      delete this.question_images[question_index]\n    }\n    this.data.questions[question_index].image = null\n    this._build_question_from_data()\n  }\n\n  _change_input_question_image(event) {\n    let question_index = event.target.question_index\n    if (event.target.files.length > 0) {\n      let reducer = new window.ImageBlobReduce({\n        pica: window.ImageBlobReduce.pica({ features: [ 'js', 'wasm', 'ww' ] })\n      });\n      reducer.toBlob(\n        event.target.files[0], {max: 1000}\n      ).then(\n        blob => {\n          let url = URL.createObjectURL(blob)\n          let reduced_file = new File([blob], event.target.files[0].name, {type:\"mime/type\", lastModified:new Date().getTime()})\n          let data_transfer = new DataTransfer()\n          data_transfer.items.add(reduced_file)\n          let question = this.data.questions[question_index]\n          let question_image = {\n            url: url,\n            file: null,\n            question_uuid: question.uuid,\n          }\n          this.question_images[question_index] = question_image\n          this._build_question_from_data()\n          let question_image_input = document.querySelector(`#action-question-image-${question_index}-input`)\n          question_image_input.files = data_transfer.files\n          this.question_images[question_index].file = question_image_input.files[0]\n          this.manager.engine.hide_modal()\n        }\n      )\n      .catch(\n        error => {console.log(error)}\n      )\n    }\n  }\n\n  _prepare_question_inputs(question, question_data, fields) {\n    let question_id = this._get_question_id(question.index)\n    for (let field of fields) {\n      let element = question.querySelector(`#query-${this.view_type}-${question_id}-${field}-input`)\n      element.field = field\n      element.index = question.index\n      element.question = true\n      if (field === \"required\") {\n        element.checked = question_data[field]\n      } else {\n        element.value = question_data[field]\n      }\n      if (this.can_edit_questions) {\n        element.addEventListener(\"input\", this._change_input, false)\n      } else {\n        element.setAttribute(\"disabled\", true)\n      }\n    }\n    for (let node of question.querySelectorAll(\".textarea-wrap\")) {\n      let input = node.querySelector(\"textarea\")\n      let value = input.value? input.value: input.placeholder\n      node.dataset.replicatedValue = value\n    }\n  }\n\n  _set_question_error_containers (question) {\n    let base_id = \"query-create\"\n    if (!this.error_containers.questions) {\n      this.error_containers.questions = {}\n    }\n    if (!this.error_containers.questions[question.index]) {\n      this.error_containers.questions[question.index] = {}\n    }\n    let fields = [\"name\", \"description\"]\n    if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question.kind)) {\n      fields.push(\"options\")\n    }\n    for (let field of fields) {\n      this.error_containers.questions[question.index][field] = question.querySelector(\n        `#query-${this.view_type}-question-${question.index}-${field}-error`\n      )\n    }\n  }\n\n  _set_disable_edit_questions (question) {\n    for (let input of question.querySelectorAll(\"input\")) {\n      input.setAttribute(\"disabled\", true)\n    }\n  }\n\n  _click_remove_question(event) {\n    let question = event.target.closest(\".question-item\")\n    this.data.questions.splice(question.index, 1)\n    this._build_question_from_data()\n  }\n\n  _set_question_options (question, question_data) {\n    let question_content = question.querySelector(\".question-item-content\")\n    let options_container = document.createElement(\"div\")\n    options_container.classList.add(\".question-options-container\")\n    options_container.innerHTML = `\n      <div class=\"question-option-list\"></div>\n      <div class=\"error-label\" id=\"query-${this.view_type}-question-${question.index}-options-error\"></div>\n      <div class=\"question-option-add\">+ Agregar opción</div>\n    `\n    let question_add_button = options_container.querySelector(\".question-option-add\")\n    question_add_button.index = question.index\n    question_add_button.addEventListener(\"click\", this._click_question_add_option, false)\n    question_content.appendChild(options_container)\n    let option_list = options_container.querySelector(`.question-option-list`)\n    let option_index = 0\n    for (let option_data of this.data.questions[question.index].options) {\n      let option = document.createElement(\"div\")\n      option.classList.add(\"question-option\")\n      let option_id = `query-${this.view_type}-question-option-${question.index}-${option_index}`\n      option.innerHTML = `\n      <div class=\"question-option-main-content\">\n        <div class=\"question-option-label\">${this.manager.letters[option_index]}.</div>\n        <input id=\"${option_id}\" type=\"text\" class=\"question-option-input\" placeholder=\"Opción ${option_index + 1}\">\n        <div class=\"question-option-delete\">X</div>\n      </div>\n      `\n      option.option_index = option_index\n      let input = option.querySelector(\".question-option-input\")\n      input.field = \"question-option\"\n      input.index = question.index\n      input.question = true\n      input.option_index = option_index\n      input.value = option_data.name\n      input.addEventListener(\"input\", this._change_input, false)\n      let delete_button = option.querySelector(\".question-option-delete\")\n      if (this.can_edit_questions) {\n        delete_button.option_index = option_index\n        delete_button.addEventListener(\"click\", this._click_question_remove_option, false)\n      } else {\n        delete_button.remove()\n      }\n      option_index += 1\n      if (question_data.kind === \"SELECT_IMAGE\") {\n        this._set_question_option_image(option, option_data, question_data)\n      }\n      option_list.appendChild(option)\n    }\n  }\n\n  _click_question_remove_option(event) {\n    let question = event.target.closest(\".question-item\")\n    this.data.questions[question.index].options.splice(event.target.option_index, 1)\n    let question_option_image = this._get_question_option_image(question.index, event.target.option_index)\n    if (question_option_image != null) {\n      question_option_image.cropper.destroy()\n      this._remove_question_option_image(question.index, event.target.option_index)\n    }\n    this._build_question_from_data()\n    this.validate_inputs()\n    this._set_errors_message()\n  }\n\n  _set_question_option_image(option, option_data, question_data) {\n    let image_widget = document.createElement(\"div\")\n    image_widget.classList.add(\"question-option-image-widget\")\n    let input_id = `question-option-image-input-${question_data.order}-${option_data.order}`\n    image_widget.innerHTML = `\n      <label for=\"${input_id}\">\n        <div class=\"question-option-image-input icon image\"></div>\n      </label>\n      <input\n        type=\"file\"\n        accept=\"image/*\"\n        class=\"hidden\"\n        id=\"${input_id}\"\n      >\n    `\n    image_widget.addEventListener(\"input\", this._click_question_option_image, false)\n    let image_preview = document.createElement(\"div\")\n    image_preview.innerHTML = `\n      <img class=\"question-option-image\" id=\"question-option-image-${question_data.order}-${option_data.order}\">\n    `\n    image_preview.classList.add(\"question-option-image-preview\")\n    option.appendChild(image_preview)\n    let image_element = image_preview.querySelector(`.question-option-image`)\n    let question_option_image = this._get_question_option_image(question_data.order, option_data.order)\n    if (question_option_image != null) {\n      image_element.setAttribute(\"src\", question_option_image.url)\n      let cropper_data = question_option_image.cropper? question_option_image.cropper.getData(): {}\n      question_option_image.cropper = new Cropper(image_element, {\n        aspectRatio: 1.333,\n        viewMode: 2,\n        data: cropper_data,\n        movable: false,\n        zoomable: false,\n        rotatable: false,\n        scalable: false,\n      })\n    }\n    else if (option_data.image) {\n      image_element.setAttribute(\"src\", option_data.image)\n    } else {\n      image_preview.classList.add(\"hidden\")\n    }\n    option.querySelector(\".question-option-main-content\").insertBefore(image_widget, option.querySelector(\".question-option-delete\"))\n  }\n\n  _get_question_option_image (question_index, option_index) {\n    for (let data of this.question_option_images) {\n      if (question_index === data.question_index && option_index === data.option_index) {\n        return data\n      }\n    }\n    return null\n  }\n\n  _set_internal_question_option_image (question_index, option_index, value) {\n    let founded_index = null\n    for (let index in this.question_option_images) {\n      let data = this.question_option_images[index]\n      if (question_index === data.question_index && option_index === data.option_index) {\n        founded_index = index\n      }\n    }\n    if (founded_index != null) {\n      this.question_option_images[founded_index] = value\n    } else {\n      this.question_option_images.push(value)\n    }\n  }\n\n  _remove_question_option_image (question_index, option_index) {\n    let index_for_remove = null\n    for (let index in this.question_option_images) {\n      let data = this.question_option_images[index]\n      if (question_index === data.question_index && option_index === data.option_index) {\n        index_for_remove = index\n      }\n    }\n    if (index_for_remove != null) {\n      this.question_option_images.splice(index_for_remove, 1)\n    }\n  }\n\n  _remove_all_question_option_image () {\n    for (let data of this.question_option_images) {\n      data.cropper.destroy()\n    }\n    this.question_option_images = []\n  }\n\n  _click_question_option_image(event) {\n    let question_item = event.target.closest(\".question-item\")\n    let option_item = event.target.closest(\".question-option\")\n    if (event.target.files.length > 0) {\n      let reducer = new window.ImageBlobReduce({\n        pica: window.ImageBlobReduce.pica({ features: [ 'js', 'wasm', 'ww' ] })\n      })\n      reducer.toBlob(\n        event.target.files[0], {max: 1000}\n      ).then(\n        blob => {\n          let reduced_file = new File([blob], event.target.files[0].name, {type:\"mime/type\", lastModified:new Date().getTime()})\n          let data_transfer = new DataTransfer()\n          event.target.files = data_transfer.files\n          let url = URL.createObjectURL(blob)\n          let question_option_image = {\n            file: event.target.files[0],\n            url: url,\n            question_index: question_item.index,\n            option_index: option_item.option_index,\n          }\n          this._set_internal_question_option_image(\n            question_item.index, option_item.option_index, question_option_image\n          )\n          this._build_question_from_data()\n          this.validate_inputs()\n        }\n      )\n      .catch(\n        error => {console.log(error)}\n      )\n    }\n  }\n\n  _set_question_max_answers (question, question_data) {\n    let actions = question.querySelector(\".question-item-actions .actions-bottom\")\n    actions.innerHTML = `\n      <div class=\"action-max-answers dropdown-wrapper\">\n        <div class=\"action-max-answers-button\">\n          <span class=\"action-label\">Cantidad de respuestas</span> <i class=\"icon bottom\"></i>\n        </div>\n        <div class=\"action-max-answers-dropdown hidden dd-content\"></div>\n      </div>\n    ` + actions.innerHTML\n    let button = actions.querySelector(\".action-max-answers-button\")\n    button.addEventListener(\"click\", this._click_question_max_answers_menu, false)\n    let dropdown = actions.querySelector(\".action-max-answers-dropdown\")\n    for (let i = 0; i < 5; i++) {\n      let option = document.createElement(\"div\")\n      option.classList.add(\"action-max-answers-option\")\n      option.value = i + 1\n      let message = `${i + 1} respuesta`\n      if (option.value == this.data.questions[question.index].max_answers) {\n        actions.querySelector(\".action-label\").innerText = message\n      }\n      if (i > 0) { message += \"s\" }\n      option.innerText = message\n      option.addEventListener(\"click\", this._click_question_max_answers_set, false)\n      dropdown.appendChild(option)\n    }\n  }\n\n  _click_question_add_option (event) {\n    let question = event.target.closest(\".question-item\")\n    let question_data = this.data.questions[question.index]\n    let order = question_data.options.length\n    if (question_data.kind === \"SELECT_IMAGE\" && order >= 4) {\n      return\n    }\n    let empty_option = {\n      name: null, order: order\n    }\n    if (question_data.kind === \"SELECT_IMAGE\") {\n      empty_option.name = `Opción ${order + 1}`\n    }\n    this.data.questions[question.index].options.push(empty_option)\n    this._build_question_from_data()\n    this.validate_inputs()\n    this._set_errors_message()\n  }\n\n  _click_question_max_answers_menu(event) {\n    let question = event.target.closest(\".question-item\")\n    let dropdown = question.querySelector(\".action-max-answers-dropdown\")\n    if (this.can_edit_questions) {\n      if (dropdown.classList.contains(\"hidden\")) {\n        dropdown.classList.remove(\"hidden\")\n      } else {\n        dropdown.classList.add(\"hidden\")\n      }\n    }\n  }\n\n  _click_question_max_answers_set (event) {\n    let question = event.target.closest(\".question-item\")\n    let button_label = question.querySelector(\".action-max-answers .action-label\")\n    let dropdown = question.querySelector(\".action-max-answers-dropdown\")\n    this.data.questions[question.index].max_answers = event.target.value\n    button_label.innerText = event.target.innerText\n    dropdown.classList.add(\"hidden\")\n  }\n\n  _set_question_draggable (question) {\n    let container = question.querySelector(\".question-container\")\n    container.draggable = true\n    container.ondragstart = this._move_question_ondragstart\n    container.ondragend = this._move_question_ondragend\n    let move_previous = question.querySelector(\".question-move-previous\")\n    let move_next = question.querySelector(\".question-move-next\")\n    move_previous.ondragenter = () => move_previous.classList.add(\"active\")\n    move_previous.ondragleave = () => move_previous.classList.remove(\"active\")\n    move_next.ondragenter = () => move_next.classList.add(\"active\")\n    move_next.ondragleave = () => move_next.classList.remove(\"active\")\n    move_previous.ondragover = (event) => event.preventDefault()\n    move_previous.ondrop = this._move_question_ondrop\n    move_previous.kind = \"previous\"\n    move_next.ondragover = (event) => event.preventDefault()\n    move_next.kind = \"next\"\n    move_next.ondrop = this._move_question_ondrop\n  }\n\n  _move_question_ondragstart(event) {\n    if (event.target.classList.contains(\"query-map-pointer\")) {\n      return\n    }\n    let question = event.target.closest(\".question-item\")\n    let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`)\n    this.current_pos = question.index\n    setTimeout(()=> { question.style.display = \"none\"}, 0)\n    questions_container.style.heigth = questions_container.clientHeigth - question.clientHeigth + \"px\"\n  }\n\n  _move_question_ondragend (event) {\n    let questions_container = document.querySelector(`#query-${this.view_type}-questions-tab`)\n    for (let question of questions_container.children) {\n      question.style.display = \"flex\"\n      question.querySelector(\".question-move-previous\").classList.remove(\"active\")\n      question.querySelector(\".question-move-next\").classList.remove(\"active\")\n    }\n  }\n\n  _move_question_ondrop(event) {\n    event.preventDefault()\n    let question = event.target.closest(\".question-item\")\n    let kind = event.target.kind\n    let total_questions = this.data.questions.length\n    let to_index = null\n    if (kind == \"previous\") {\n      to_index = question.index - 1 < 0? 0 : question.index\n    }\n\n    else if (kind == \"next\") {\n      to_index = question.index\n    }\n    if (this.current_pos === to_index) {\n      return\n    }\n    let questions = [...this.data.questions]\n    let moved_question = {...questions[this.current_pos]}\n    questions = questions.filter(q => q.order != moved_question.order)\n    questions.splice(to_index, 0, moved_question)\n    this.data.questions = questions\n    this._set_question_data_order()\n    this._build_question_from_data()\n  }\n\n  _set_question_data_order () {\n    let index = 0\n    for (let question of this.data.questions) {\n      question.order = index\n      index += 1\n    }\n  }\n\n  set_can_edit_active_status () {\n    let active = document.querySelector(`#query-${this.view_type}-active`)\n    let status_container = active.closest(\".status\")\n    if (!this.manager.engine.user.is_superuser) {\n       status_container.style.display = \"none\"\n    } else {\n       status_container.style.display = \"flex\"\n    }\n  }\n\n  async _upload_question_images() {\n    for (let question_index in this.question_images) {\n      let question_image = this.question_images[question_index]\n      let question_uuid = question_image.question_uuid? question_image.question_uuid: this.data.questions[question_index].uuid\n      let data = new FormData()\n      data.append(\"question_uuid\", question_uuid)\n      if (question_image.file) {\n        data.append(\"image\", question_image.file)\n      }\n      await fetch(this.manager.url_base + \"update_question_image/\", {\n        method: \"POST\",\n        body: data,\n        headers: {\"X-CSRFToken\": this.manager.engine.csrf_token},\n        credentials: \"same-origin\"\n      })\n    }\n  }\n\n  async _upload_question_option_images() {\n    for (let option_data of this.question_option_images) {\n      let question = this.data.questions[option_data.question_index]\n      let option = question.options[option_data.option_index]\n      if (option_data.cropper) {\n        let canvas = option_data.cropper.getCroppedCanvas()\n        let blob = await new Promise(resolve => canvas.toBlob(resolve));\n        let data = new FormData()\n        data.append(\"option_uuid\", option.uuid)\n        data.append(\"image\", blob, `${option.uuid}.jpg`)\n        await fetch(this.manager.url_base + \"update_question_option_image/\", {\n          method: \"POST\",\n          body: data,\n          headers: {\"X-CSRFToken\": this.manager.engine.csrf_token},\n          credentials: \"same-origin\"\n        })\n      }\n    }\n  }\n}\n\n\nclass QueryCreateManager extends QueryEditBase {\n  _set_initial() {\n    this.view_type = \"create\"\n  }\n\n  show_view(on_history) {\n    this.manager.engine._hide_all_views()\n    this.manager.engine.blocked = true\n    this.manager._build_sidebar()\n    this._clean_data()\n    this.set_can_edit_active_status()\n    this.manager.engine.views.query_create.classList.remove(\"hidden\")\n    if (on_history) {\n      this.manager.engine._set_url_params(\"query-create\", null)\n    }\n  }\n\n  execute_service() {\n    fetch(this.manager.url_base, {\n      method: \"POST\",\n      body: JSON.stringify(this.data),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response) => {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          if (data.uuid) {\n            this.manager.engine.blocked = false\n            this.data = data\n            this._upload_question_images().then((a) => {\n              this._upload_question_option_images().then((b) => {\n                this.manager.engine.cursor.key = data.uuid\n                this.manager.engine.set_navbar_message(\"Consulta creada correctamente\", 4000)\n                this.manager.engine.show_view(\"query-detail\", true)\n                this._clean_data()\n              })\n            })\n          } else {\n            console.log(data)\n          }\n        })\n      } else {\n        response.json()\n        .then((data)=> {\n          this.errors = {...this.errors, ...data}\n          this._set_errors_message()\n          this.manager.engine._hide_all_views()\n          this.manager.engine.views.query_create.classList.remove(\"hidden\")\n        })\n      }\n    })\n  }\n}\n\nclass QueryUpdateManager extends QueryEditBase {\n  _set_initial() {\n    this.view_type = \"update\"\n    this._click_query_delete_modal = this._click_query_delete_modal.bind(this)\n    this._click_query_delete = this._click_query_delete.bind(this)\n    this._click_remove_question_modal = this._click_remove_question_modal.bind(this)\n    let query_delete_button = document.querySelector(\"#update-query-delete-button\")\n    query_delete_button.addEventListener(\"click\", this._click_query_delete_modal, false)\n  }\n\n  _click_query_delete_modal(event) {\n    let config = {\n      class: \"query-delete-confirmation\",\n      icon: \"alert\",\n      title: \"¿Estás seguro de que quieres eliminar esta consulta?\",\n      content: `Se perderán todas las respuestas (${this.total_responses}) y datos asociados a esta consulta de manera permanente`,\n      actions: [\n        {name: \"Sí\", click: this._click_query_delete},\n        {name: \"No\", click: this.manager.engine.hide_modal},\n      ],\n    }\n    this.manager.engine.show_modal(config)\n  }\n\n  _click_query_delete(event) {\n    this.manager.engine._set_loading()\n    this.manager.engine.hide_modal()\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}`, {\n      method: \"DELETE\",\n      body: JSON.stringify({\"confirmation\": \"TRUE\"}),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        this.manager.engine.blocked = false\n        response.json()\n        .then((data)=> {\n          this.manager.engine.set_navbar_message(\"Consulta borrada correctamente\", 4000)\n          this.manager.engine.show_view(\"query-list\", true)\n        })\n      } else {\n        console.log(response)\n        this.manager.engine.show_view(\"query-update\", true)\n      }\n    })\n  }\n\n  _get_question_delete_callback() {\n    return this._click_remove_question_modal\n  }\n\n  _click_remove_question_modal(event) {\n    let question = event.target.closest(\".question-item\")\n    let config = {\n      class: \"query-delete-confirmation\",\n      icon: \"alert\",\n      title: \"¿Estás seguro de que quieres eliminar esta pregunta?\",\n      content: `Se perderán todas las respuestas y datos asociados a esta pregunta de manera permanente`,\n      actions: [\n        {name: \"Sí\", click: this._click_remove_question},\n        {name: \"No\", click: this.manager.engine.hide_modal},\n      ],\n      data: {question_index: question.index }\n    }\n    this.manager.engine.show_modal(config)\n  }\n\n  _click_remove_question(event) {\n    let modal_data = event.target.closest(\"#admin-modal\").config.data\n    let question_index = modal_data.question_index\n    this.data.questions.splice(question_index, 1)\n    this._build_question_from_data()\n    this.manager.engine.hide_modal()\n  }\n\n  show_view(on_history) {\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.manager.engine.blocked = true\n          this._set_in_view(data)\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-update\", data.query.url_code)\n          }\n        })\n      } else {\n        console.log(response)\n        this.manager.engine._set_url_params(\"query-list\")\n        this.manager.engine.show_view(\"query-list\", false)\n      }\n    })\n  }\n\n  _set_done (data) {\n    this.manager.engine.cursor.key = data.uuid\n    this.manager.engine.set_navbar_message(\"Consulta editada correctamente\", 4000)\n    this.manager.engine.show_view(\"query-detail\", true)\n    this._clean_data()\n  }\n\n  execute_service () {\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}/`, {\n      method: \"PUT\",\n      body: JSON.stringify(this.data),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response) => {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          if (data.uuid) {\n            this.manager.engine.blocked = false\n            this.data = data\n            this._upload_question_images().then((a) => {\n              this._upload_question_option_images().then((b) => {\n                this.manager.engine.cursor.key = data.uuid\n                this.manager.engine.set_navbar_message(\"Consulta editada correctamente\", 4000)\n                this.manager.engine.show_view(\"query-detail\", true)\n                this._clean_data()\n              })\n            })\n          } else {\n            console.log(data)\n          }\n        })\n      } else {\n        response.json()\n        .then((data)=> {\n          this.errors = {...this.errors, ...data}\n          this._set_errors_message()\n          this.manager.engine._hide_all_views()\n          this.manager.engine.views.query_update.classList.remove(\"hidden\")\n        })\n      }\n    })\n  }\n\n  _set_in_view (data) {\n    this.data = {\n        uuid: data.query.uuid,\n        name: data.query.name,\n        description: data.query.description,\n        start_at: data.query.start_at,\n        end_at: data.query.end_at,\n        active: data.query.active,\n        auth_email: data.query.auth_email,\n        auth_rut: data.query.auth_rut,\n        questions: [],\n    }\n    this.total_responses = data.query.total_responses\n    let questions = Array.isArray(data.query.questions)? data.query.questions: []\n    for (let question of questions) {\n      let cleaned_question = this._get_cleaned_question(question)\n      this.data.questions.push(cleaned_question)\n    }\n    for (let field in this.inputs) {\n      let input = this.inputs[field]\n      if ([\"start_at\", \"end_at\"].includes(field) && this.data[field]) {\n        input.value = new Date(this.data[field]).toISOString().split('T')[0]\n      } else {\n        input.value = this.data[field]\n      }\n      if ([\"name\"].includes(field)) {\n        input.parentNode.dataset.replicatedValue = this.data[field]\n      }\n    }\n    this.set_can_edit_active_status()\n    this.can_edit_questions = data.query.can_edit_questions\n    if (!this.can_edit_questions) {\n      this.buttons.new_question.disabled = true\n      this.buttons.new_question.classList.add(\"disabled\")\n    }\n    this._build_question_from_data()\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_update.classList.remove(\"hidden\")\n  }\n\n  _get_cleaned_question (question) {\n    let cleaned_question = {\n      uuid: question.uuid,\n      kind: question.kind,\n      name: question.name,\n      description: question.description,\n      required: question.required,\n      order: question.order,\n      image: question.image,\n    }\n    if (question.kind == \"TEXT\") {\n      cleaned_question.text_max_length = question.text_max_length\n    } else if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question.kind)) {\n      cleaned_question.max_answers = question.max_answers\n      cleaned_question.options = question.options\n    } else if (question.kind == \"POINT\") {\n      let default_point = {\n        latitude: -33.447869, longitude: -70.668423\n      }\n      cleaned_question.default_point = question.default_point? question.default_point: default_point\n      cleaned_question.default_zoom = question.default_zoom? question.default_zoom: 9\n    }\n    return cleaned_question\n  }\n}\n\n\nexport {QueryCreateManager, QueryUpdateManager}\n","function get_chart (config) {\n    let id = config.id\n    let type = config.type\n    let values = config.values\n    let labels = config.labels\n    let options = config.options? config.options: {}\n    let barColors = [\n        \"#c1368c\", \"#a34895\",\"#6f448c\",\"#495599\",\"#54baae\"\n    ]\n    let data = {\n        labels: labels,\n        datasets: [\n            {backgroundColor: barColors, data: values, label: config.label}\n        ]\n    }\n    options.scales = {x: {ticks: {display: false}, grid: {display: false}}, y: {ticks:{display: false}}}\n    options.plugins = {\n        datalabels: {color: \"#fff\"}, legend: {display: false}, tooltip: {enabled: false}\n    }\n    options.animation = {duration: 0}\n    Chart.register(ChartDataLabels)\n    let chart = new Chart(id, {\n        type: type,\n        data: data,\n        options: options,\n    })\n    let labels_container = document.querySelector(`#${id}-labels`)\n    let color_index = 0\n    let value_index = 0\n\n    for (let label of labels) {\n        let element = document.createElement(\"div\")\n        element.classList.add(\"chart-label-container\")\n        let color_element = document.createElement(\"div\")\n        color_element.classList.add(\"chart-label-color\")\n        if (color_index >= barColors.length) {color_index = 0}\n        color_element.style.backgroundColor = barColors[color_index]\n        element.appendChild(color_element)\n        let label_value = document.createElement(\"div\")\n        label_value.classList.add(\"chart-label-value\")\n        label_value.textContent = `${values[value_index]} - ${label}`\n        element.appendChild(label_value)\n        labels_container.append(element)\n        color_index += 1\n        value_index += 1\n    }\n    labels_container.classList.remove(\"hidden\")\n    return chart\n}\n\nexport {get_chart}\n","import {\n  get_chart\n} from \"../charts.js\"\n\nclass QueryResultManager {\n  constructor ({manager = null, kind = null}) {\n    this.manager = manager\n    this.data = {}\n    this.kind = kind\n    this.charts = {summary: null, questions: []}\n    this.map = null\n    this.data_table = null\n    this.marker_focus = null\n    this.map_markers = {}\n    this._click_download_link = this._click_download_link.bind(this)\n    this._click_download_dropdown = this._click_download_dropdown.bind(this)\n    this._click_map_shapes_button = this._click_map_shapes_button.bind(this)\n    this._click_map_shape_action = this._click_map_shape_action.bind(this)\n    this._click_response_visibility = this._click_response_visibility.bind(this)\n    this._set_row_callback = this._set_row_callback.bind(this)\n    this._set_pre_in_view()\n  }\n\n  _set_pre_in_view () {\n    let tab_links = document.querySelector(`.view.query-${this.kind} .result.tab-links`)\n    let click_got_to = this.manager._click_go_to_view.bind(this.manager)\n    for (let tab_link of tab_links.children) {\n      tab_link.addEventListener(\"click\", click_got_to, false)\n    }\n    this._set_download_links()\n  }\n\n  _set_download_links () {\n    let dropdown_button = document.querySelector(`#query-${this.kind}-download-button`)\n    dropdown_button.addEventListener(\"click\", this._click_download_dropdown, false)\n    let excel_link = document.querySelector(`#query-${this.kind}-download-excel`)\n    excel_link.kind = \"excel\"\n    let geojson_link = document.querySelector(`#query-${this.kind}-download-geojson`)\n    geojson_link.kind = \"geojson\"\n    let images_link = document.querySelector(`#query-${this.kind}-download-images`)\n    images_link.kind = \"images-zip\"\n    for (let element of [excel_link, geojson_link, images_link]) {\n      element.addEventListener(\"click\", this._click_download_link, false)\n    }\n  }\n\n  _click_download_dropdown (event) {\n    let dropdown_content = document.querySelector(`#query-${this.kind}-dropdown`)\n    if (dropdown_content.classList.contains(\"hidden\")) {\n      dropdown_content.classList.remove(\"hidden\")\n    } else {\n      dropdown_content.classList.add(\"hidden\")\n    }\n  }\n\n  _click_download_link (event) {\n    let kind = event.target.kind\n    if ([\"geojson\", \"excel\"].includes(kind)) {\n      let link = `${this.manager.url_base}${this.manager.engine.cursor.key}/${event.target.kind}/`\n      window.open(link)\n    }\n    if (kind === \"images-zip\") {\n      this._donwload_images()\n    }\n    document.querySelector(`#query-${this.kind}-dropdown`).classList.add(\"hidden\")\n  }\n\n  _donwload_images () {\n    const _get_image_fields = (data) => {\n      let images_fields = []\n      for (let question of data.query.questions) {\n        if (question.kind === \"IMAGE\") {\n          let field = `pregunta_${question.index + 1}`\n          images_fields.push(field)\n        }\n      }\n      return images_fields.length === 0 ? null : images_fields\n    }\n\n    const _get_image_data_list = (data, fields) => {\n      let image_data_list = []\n      for (let response of data.dataset) {\n        if (response.visible === \"True\") {\n          let base_data = {\n            \"response\": {send_at: response.send_at, uuid: response.uuid}\n          }\n          for (let field of fields) {\n            let original = response[field] === \"\" ? null : response[field].original\n            if (original) {\n              let url = response[field].thumb_medium\n              let extension = url.slice(url.length - 3)\n              let image_data = {...base_data, url, extension, field}\n              image_data_list.push(image_data)\n            }\n          }\n        }\n      }\n      return image_data_list.length > 0 ? image_data_list : null\n    }\n\n    const _create_async_download = (image_data) => {\n      return new Promise((resolve, reject) => {\n        let image_blob = fetch(image_data.url).then(response => response.blob());\n        resolve({...image_data, blob: image_blob})\n      })\n    }\n\n    const _download_image_callback = (results, query_url_code) => {\n      let zip = new JSZip()\n      let folder = zip.folder(\"images\")\n      for (let image_data of results) {\n        let response = image_data.response\n        let filename = `${response.send_at}-${image_data.field}-${response.uuid}.${image_data.extension}`\n        folder.file(filename, image_data.blob)\n      }\n      folder.generateAsync({type: \"blob\"}).then(content => saveAs(content, `consulta-imagenes-${query_url_code}-${new Date().toLocaleDateString()}`))\n    }\n\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}/data/`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          let images_fields = _get_image_fields(data)\n          let image_data_list = _get_image_data_list(data, images_fields)\n          let tasks = []\n          for (let image_data of image_data_list) {\n            let task = _create_async_download(image_data)\n            tasks.push(task)\n          }\n          let results = []\n          let task_completed = 0\n          tasks.forEach((task) => {\n            task.then((value)=> {\n              results.push(value)\n            })\n            .catch((error)=> console.log(error))\n            .finally(() => {\n              task_completed++\n              if (task_completed >= tasks.length) {\n                _download_image_callback(results, data.query.url_code)\n              }\n            })\n          })\n        })\n      } else {\n        console.log(response)\n      }\n    })\n  }\n\n  show_view(on_history) {\n    let suffix = `${[\"result\", \"questions\"].includes(this.kind)? '' : this.kind}`\n    fetch (`${this.manager.url_base}${this.manager.engine.cursor.key}/${suffix}`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.data = data\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(`query-${this.kind}`, data.query.url_code)\n          }\n        })\n      } else {\n        console.log(response)\n        this.manager.engine.show_view(\"query-list\", false)\n      }\n    })\n  }\n\n  _set_in_view() {\n    this.manager._build_sidebar()\n    if (this.kind == \"result\") {\n      this._set_summary()\n    } else if (this.kind == \"questions\") {\n      this._set_questions()\n    } else if (this.kind == \"map\") {\n      this._set_map()\n    } else if (this.kind == \"data\") {\n      this._set_datatables()\n    }\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views[`query_${this.kind}`].classList.remove(\"hidden\")\n  }\n\n  _set_summary () {\n    if (this.charts.summary) {\n      this.charts.summary.destroy()\n    }\n    document.querySelector(\"#query-result-summary .content\").innerHTML = \"\"\n    document.querySelector(\"#result-summary-chart-labels\").innerHTML = \"\"\n    document.querySelector(\"#result-summary-chart\").classList.add(\"hidden\")\n    document.querySelector(\n      \"#query-result .responses-total .total-value\"\n    ).textContent = this.data.total_responses\n    let summary_answer = this._get_first_select_result()\n    if (summary_answer) {\n      let answer_labels = summary_answer.options.map((x)=> x.option_name)\n      let answer_values = summary_answer.options.map((x)=> x.total)\n      let options = {indexAxis: \"x\"}\n      let chart = get_chart({\n        id: \"result-summary-chart\",\n        type: \"bar\",\n        labels: answer_labels,\n        values: answer_values,\n        options\n      })\n      document.querySelector(\"#result-summary-chart\").classList.remove(\"hidden\")\n      this.charts.summary = chart\n    }\n  }\n\n  _get_first_select_result () {\n    let result = null\n    for (let answer_result of this.data.answer_results) {\n      if ([\"SELECT\", \"SELECT_IMAGE\"].includes(answer_result.question.kind)) {\n        result = answer_result\n        break\n      }\n    }\n    return result\n  }\n\n  _set_questions() {\n    document.querySelector(\"#query-result-questions .content\").innerHTML = \"\"\n    let questions_container = document.querySelector(\"#query-result-questions\")\n    let content = questions_container.querySelector(\".content\")\n    for (let chart of this.charts.questions) {\n      chart.destroy()\n    }\n    this.charts.questions = []\n    for (let answer_result of this.data.answer_results) {\n      let template = questions_container.querySelector(\"#result-question-template\").cloneNode(true)\n      template.removeAttribute(\"id\")\n      let index = answer_result.question.index\n      template.querySelector(\".question-number .value\").textContent = index + 1\n      template.querySelector(\".question-name\").textContent = answer_result.question.name\n      template.querySelector(\".responses-total .total-value\").textContent = answer_result.total\n      content.appendChild(template)\n      if ([\"SELECT\", \"SELECT_IMAGE\"].includes(answer_result.question.kind)) {\n        let id = `result-question-chart-${index}`\n        let canvas = template.querySelector(\".question-chart\")\n        canvas.setAttribute(\"id\", id)\n        let labels = template.querySelector(\".chart-labels\")\n        labels.setAttribute(\"id\", `${id}-labels`)\n        let answer_labels = answer_result.options.map((x)=> x.option_name)\n        let answer_values = answer_result.options.map((x)=> x.total)\n        let chart = get_chart({\n          id,\n          type: \"bar\",\n          labels: answer_labels,\n          values: answer_values,\n          options: {indexAxis: \"y\"},\n        })\n        this.charts.questions.push(chart)\n        canvas.classList.remove(\"hidden\")\n        labels.classList.remove(\"hidden\")\n      }\n      template.classList.remove(\"hidden\")\n    }\n\n  }\n\n  _set_map () {\n    let map = this._get_map()\n    let question_by_uuid = {}\n    for (let question of this.data.query.questions) {\n      question_by_uuid[question.uuid] = question\n    }\n    let shapes = new Set()\n    this.marker_focus = null\n    for (let point_data of this.data.point_list) {\n      if (point_data.location && point_data.question_index !== null) {\n        shapes.add(point_data.question_index)\n        this._set_marker(map, question_by_uuid, point_data)\n      }\n    }\n    if (this.marker_focus) {\n      let marker = this.marker_focus\n      setTimeout(function () {\n        marker.openPopup();\n      }, 100);\n    }\n    this._set_map_shapes(Array.from(shapes))\n    this._set_fetch_meta()\n  }\n\n  _get_map () {\n    if (this.map) {\n      this.map.remove()\n    }\n    document.querySelector(\"#query-result-map\").innerHTML = \"\"\n    let latlng = L.latLng(-33.447869, -70.668423)\n    let map = L.map(\"query-result-map\").setView(latlng, 9)\n    L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png', {\n      maxZoom: 19,\n    }).addTo(map);\n    map.attributionControl.setPrefix(\"\")\n    map.zoomControl.setPosition(\"bottomright\")\n    setTimeout(function () {\n      window.dispatchEvent(new Event('resize'));\n    }, 100);\n    this.map = map\n    return map\n  }\n\n  _set_map_shapes (shapes) {\n    let shape_bottom = document.querySelector(\"#map-shapes-control .map-shapes-button\")\n    shape_bottom.active = false\n    shape_bottom.addEventListener(\"click\", this._click_map_shapes_button)\n    let shape_list = document.querySelector(\"#map-shapes-control-list\")\n    shape_list.innerHTML = \"\"\n    let counter = 0\n    for (let shape of shapes) {\n      let shape_element = document.createElement(\"div\")\n      shape_element.classList.add(\"map-shape-element\")\n      let icon_counter = counter < 3 ? counter: 0\n      shape_element.innerHTML = `\n        <div class=\"marker-preview-icon\" counter=\"${icon_counter}\"></div>\n        <div class=\"map-shape-label\">Pregunta ${counter + 1}</div>\n        <div class=\"map-shape-icon icon switch-on\"></div>\n      `\n      shape_list.appendChild(shape_element)\n      shape_element.question_index = shape\n      shape_element.active = true\n      shape_element.querySelector(\".icon\").addEventListener(\"click\", this._click_map_shape_action)\n      counter += 1\n    }\n  }\n\n  _click_map_shapes_button(event) {\n    let shape_list = document.querySelector(\"#map-shapes-control-list\")\n    let shape_bottom = document.querySelector(\"#map-shapes-control .map-shapes-button\")\n    let bottom_icon = shape_bottom.querySelector(\".icon\")\n    if (shape_bottom.active) {\n      shape_bottom.active = false\n      shape_list.classList.add(\"hidden\")\n      bottom_icon.classList.remove(\"back\")\n      bottom_icon.classList.add(\"right\")\n    } else {\n      shape_bottom.active = true\n      shape_list.classList.remove(\"hidden\")\n      bottom_icon.classList.remove(\"right\")\n      bottom_icon.classList.add(\"back\")\n    }\n  }\n\n  _click_map_shape_action (event) {\n    let shape_element = event.target.closest(\".map-shape-element\")\n    let action_icon = shape_element.querySelector(\".map-shape-icon\")\n    if (shape_element.active) {\n      shape_element.active = false\n      action_icon.classList.remove(\"switch-on\")\n      action_icon.classList.add(\"switch-off\")\n      this._set_map_shape_visibility(shape_element.question_index, false)\n    } else {\n      shape_element.active = true\n      action_icon.classList.remove(\"switch-off\")\n      action_icon.classList.add(\"switch-on\")\n      this._set_map_shape_visibility(shape_element.question_index, true)\n    }\n  }\n\n  _set_map_shape_visibility(question_index, show) {\n    if (this.map_markers[question_index]) {\n      for (let marker of this.map_markers[question_index]) {\n        if (show) {\n          marker.setOpacity(1)\n        } else {\n          marker.setOpacity(0)\n        }\n      }\n    }\n  }\n\n  _set_marker(map, question_by_uuid, point_data) {\n    let icon = this._get_marker_icon(point_data, question_by_uuid)\n    let marker = L.marker(\n      [point_data.location.latitude, point_data.location.longitude], {\n        icon: icon,\n      }\n    ).addTo(map)\n    let message = \"<div class='marker-content'>\"\n    message += this._set_html_message(\"Fecha de envío\", new Date(point_data.response.send_at).toLocaleString())\n    if (point_data.response.email) {\n      message += this._set_html_message(\"Email\", point_data.response.email)\n    }\n    if (point_data.response.rut) {\n      message += this._set_html_message(\"Rut\", point_data.response.rut)\n    }\n    message += this._get_answers_message(point_data, question_by_uuid)\n    message += '</div>'\n    marker.bindPopup(message)\n    let current_markers = this.map_markers[point_data.question_index] ? this.map_markers[point_data.question_index]: []\n    this.map_markers[point_data.question_index] = [...current_markers, marker]\n    let param = new URLSearchParams(window.location.search).get(\"r\")\n    if (param && param == point_data.response.uuid) {\n      this.marker_focus = marker\n    }\n  }\n\n  _get_marker_icon(point_data, question_by_uuid) {\n    let counter = 0\n    for (let question_uuid in question_by_uuid) {\n      let question = question_by_uuid[question_uuid]\n      if (point_data.question_index === question.index) {\n        break\n      }\n      if (question.kind === \"POINT\") {\n        counter += 1\n      }\n      if (counter > 2) {\n        break\n      }\n    }\n    let icon_counter = counter < 3 ? counter: 0\n    let icon_url = `/static/images/icons/marker-${icon_counter}.svg`\n    let icon = L.icon({\n      iconUrl: icon_url, iconSize: [20, 30],\n    })\n    return icon\n  }\n\n  _set_html_message(field, value, class_list) {\n    return `<div class=\"item ${class_list? class_list: \"\"}\"><div class=\"field\">${field}: </div><div class=\"value\">${value}</div></div>`\n  }\n\n  _get_answers_message (point_data, question_by_uuid) {\n    let message = \"<div class='responses-title'>Respuestas</div><div class='responses-list'>\"\n    for (let answer of point_data.response.answers) {\n      let question = question_by_uuid[answer.question_uuid]\n      message += this._set_html_message(`Pregunta ${question.index + 1}`, question.name)\n      if (question.kind == \"TEXT\") {\n        message += this._set_html_message(\"- Texto\", answer.text)\n      }\n      if (question.kind == \"IMAGE\") {\n        message += this._set_html_message(\"- Imagen\", `<img class=\"image\" src=\"${answer.image}\">`)\n      }\n      if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question.kind)) {\n        let options = \"<div class='options-list'>\"\n        for (let option of answer.options) {\n          options += `<div class=\"option\">${option.name}</div>`\n        }\n        options += \"</div>\"\n        message += this._set_html_message(\"- Opciones\", options, \"response\")\n      }\n    }\n    message += \"</div>\"\n    return message\n  }\n\n  _set_fetch_meta () {\n    if (this.data.response_range) {\n      let start = new Date(this.data.response_range[0]).toLocaleString()\n      let end = new Date(this.data.response_range[1]).toLocaleString()\n      let range_responses = `${this.data.point_list.length} respuestas del ${start} al ${end}`\n      document.querySelector(\"#query-map .range-responses\").textContent = range_responses\n    }\n    document.querySelector(\"#query-map .fetch-at\").textContent = `Consultado en ${new Date(this.data.fetch_at).toLocaleString()}`\n  }\n\n  _set_datatables () {\n    if (this.data_table) {\n      this.data_table.destroy()\n    }\n    let dataset = []\n    for (let item of this.data.dataset) {\n      let row = this._get_row_from_item(item)\n      dataset.push(row)\n    }\n    let config = {...this.data.simpletables_config}\n    config.rowRender = this._set_row_callback\n    config.data.data = dataset\n    config.data.headings = this._get_datables_heading(config)\n    this.data_table = new simpleDatatables.DataTable(\"#query-result-data-table\", config)\n    this._set_cell_options()\n    this._set_single_image_download()\n\n  }\n  _set_cell_options () {\n    for (let button of document.querySelectorAll(\".cell-options-button\")) {\n      button.addEventListener(\"click\", function () {\n        let content = this.nextElementSibling\n        if (content.classList.contains(\"hidden\")) {\n          content.classList.remove(\"hidden\")\n        } else {\n          content.classList.add(\"hidden\")\n        }\n      })\n    }\n    for (let button of document.querySelectorAll(\".dropdown-item.visiblity\")) {\n      button.addEventListener(\"click\", this._click_response_visibility, false)\n    }\n  }\n\n  _set_single_image_download() {\n    let images = document.querySelectorAll(\".query-datable-image\")\n    if (images.length > 0) {\n      for (let image of images) {\n        image.addEventListener(\"click\", function () {\n          let original_url = this.getAttribute(\"original\")\n          let send_at = this.getAttribute(\"send_at\").slice(0, 19).replace(\" \", \".\")\n          let filename = `${send_at}.png`\n          new Promise((resolve, reject) => {\n            let image_blob = fetch(original_url).then(response => response.blob());\n            resolve(image_blob)\n          }).then(blob => saveAs(blob, filename))\n        })\n      }\n    }\n  }\n\n  _click_response_visibility (event) {\n    this.manager.engine._set_loading()\n    let response_uuid = event.target.getAttribute(\"response\")\n    let current_visibility = event.target.getAttribute(\"visible\")\n    if (response_uuid == null) {\n      let dropdown_item = event.target.closest(\".dropdown-item.visiblity\")\n      response_uuid = dropdown_item.getAttribute(\"response\")\n      current_visibility = dropdown_item.getAttribute(\"visible\")\n    }\n    current_visibility = current_visibility === \"true\"\n    let data = {\n      response_uuid, visible: !current_visibility\n    }\n    fetch (`${this.manager.url_base}update_response_visibility/`, {\n      method: \"POST\",\n      body: JSON.stringify(data),\n      headers: {\"Content-Type\": \"application/json\", \"X-CSRFToken\": this.manager.engine.csrf_token},\n      credentials: \"same-origin\"\n    })\n    .then((response)=>{\n      this.show_view()\n    })\n  }\n\n  _set_row_callback (rowValue, tr, index) {\n    tr.attributes.class = \"row-response\"\n  }\n\n  _get_row_from_item(item) {\n    let row = []\n    for (let i = 0; i < this.data.fields.length; i++) {\n      let field = this.data.fields[i]\n      let value = item[field]\n      if (field == \"send_at\") {\n        let sat = new Date(value)\n        let month = sat.getMonth() + 1\n        month = month < 10 ? `0${month}`: month\n        let day = sat.getDate() < 10 ? `0${sat.getDate()}`: sat.getDate()\n        value = `${sat.getFullYear()}-${month}-${day} `\n        value += `${sat.getHours()}:${sat.getMinutes()}:${sat.getSeconds()}`\n      }\n      if (field == \"location\" && value) {\n        let lat = `<div class=\"latitude\"><span class=\"label\">Latitud: </span><span class=\"value\">${value.latitude}</span></div>`\n        let long = `<div class=\"latitude\"><span class=\"label\">Longitud: </span><span class=\"value\">${value.longitude}</span></div>`\n        value = `${lat}${long}`\n      }\n      if (field.includes(\"pregunta_\")) {\n        value = this._get_question_value(this.data.query.questions, field, value, item)\n      }\n      if (value == null) {\n        value = \"\"\n      }\n      if (field == \"visible\") {\n        let visible = value === \"True\"\n        let label = visible ? \"Ocultar respuestas\": \"Mostrar respuestas\"\n        value = `\n          <div class=\"dropdown-wrapper\">\n            <div class=\"cell-options-button icon options\"></div>\n            <div class=\"dropdown-content cell-options-content hidden dd-content\">\n              <div class=\"dropdown-item visiblity\" response=\"${item.uuid}\" visible=\"${visible}\">\n                <div class=\"icon ${visible? 'hide': 'show'}\"></div>\n                <div class=\"dropdown-item-value\">${label}</div>\n              </div>\n            </div>\n          </div>\n        `\n      }\n      row.push(value)\n    }\n    if (item.visible === \"False\") {\n      row[1] = `\n        <div class=\"response-hidden-alert\">\n          <div class=\"icon hide\"></div>\n          <div class=\"response-hidden-alert-message\">\n            <div class=\"response-hidden-title\">\n              Respuestas en modo oculto\n            </div>\n            <div class=\"response-hidden-subtitle\">\n              Las respuesta de esta persona no serán consideradas en los resultados de esta consulta.\n            </div>\n          </div>\n        </div>\n        <div class=\"response-hidden-alert-spacer\"></div>\n      `\n    }\n    return row\n  }\n\n  _get_datables_heading(config) {\n    let headings = []\n    for (let header of config.data.headings) {\n      let description = header.desc ? `<div class=\"dt-field-desc\">${header.desc}</div>`: \"\"\n      let heading = `<div class=\"dt-field\"><div class=\"dt-field-label\">${header.label}</div>${description}</div>`\n      headings.push(heading)\n    }\n    return headings\n  }\n\n  _get_question_value(questions, field, value, item) {\n    let num = parseInt(field.match(/\\d+/)[0])\n    let index = num - 1\n    let question = questions[index]\n    let final_value = value\n\n    if (question.kind == \"IMAGE\" && value) {\n      final_value = `<div class=\"query-datable-image\" style=\"background-image: url('${value.thumb}')\" send_at=\"${item.send_at}\" original=\"${value.original}\"></div>`\n    } else if (question.kind == \"POINT\" && value) {\n      let query_url_code = this.data.query.url_code\n      let link = item.visible === \"True\"? `href=\"?f=query-map&k=${query_url_code}&r=${item.uuid}\"`: \"\"\n      final_value = `\n        <div class=\"query-result-to-map\">\n          <a class=\"query-result-to-map-link\" ${link}>\n            <div class=\"icon map-marker\"></div>\n            <div class=\"to-map-link-label\">Ver en el mapa</div>\n          </a>\n        </div>\n      `\n    } else if ([\"SELECT\", \"SELECT_IMAGE\"].includes(question.kind) && value) {\n      final_value = \"<ul>\"\n      for (let opt of value) {\n        final_value += `<li>${opt}</li>`\n      }\n      final_value += \"</ul>\"\n    }\n    return final_value\n  }\n\n}\n\nexport {QueryResultManager}\n","class QueryShareManager {\n  constructor ({manager = null, kind = null}) {\n    this.manager = manager\n    this.data = {}\n\n  }\n  show_view(on_history) {\n    this.manager._build_sidebar()\n    this.manager.engine._hide_all_views()\n    this._set_in_view()\n    this.manager.engine.views.query_share.classList.remove(\"hidden\")\n    if (on_history) {\n      this.manager.engine._set_url_params(`query-share`, this.manager.engine.cursor.key)\n    }\n  }\n\n  _set_in_view() {\n    this._click_copy_link = this._click_copy_link.bind(this)\n    this._click_download_link = this._click_download_link.bind(this)\n    this._click_print_link = this._click_print_link.bind(this)\n    let copy_link = document.querySelector(\"#query-share-copy-link\")\n    copy_link.addEventListener(\"click\", this._click_copy_link, false)\n    let download_link = document.querySelector(\"#query-share-download-link\")\n    download_link.addEventListener(\"click\", this._click_download_link, false)\n    let print_link = document.querySelector(\"#query-share-print-link\")\n    print_link.addEventListener(\"click\", this._click_print_link, false)\n  }\n\n  _click_copy_link(event) {\n    let submit_link = this._get_submit_link()\n    navigator.clipboard.writeText(submit_link)\n    let action_container = event.target.closest(\".action-container\")\n    if (!action_container.querySelector(\".action-success\")) {\n      let success = document.createElement(\"div\")\n      success.classList.add(\"action-success\")\n      success.innerHTML = \"<i class='icon ok-simple'></i> Copiado correctamente\"\n      action_container.appendChild(success)\n      setTimeout(function () {\n        action_container.querySelector(\".action-success\").remove()\n      }, 3000)\n    }\n  }\n\n  _click_download_link (event) {\n    let pdf_link = this._get_pdf_link()\n    window.open(pdf_link + \"?k=download\")\n  }\n\n  _click_print_link (event) {\n    let pdf_link = this._get_pdf_link()\n    let w = window.open(pdf_link)\n    w.print()\n  }\n\n  _get_submit_link() {\n    return `https://${location.host}/submit/${this.manager.engine.cursor.key}`\n  }\n\n  _get_pdf_link () {\n    return `${this.manager.url_base}${this.manager.engine.cursor.key}/share/`\n  }\n}\n\nexport {QueryShareManager}\n","class QueryAPIManager {\n  constructor ({manager = null, kind = null}) {\n    this.manager = manager\n    this.api_config = {}\n    this._click_copy_link = this._click_copy_link.bind(this)\n    this._get_curl_example = this._get_curl_example.bind(this)\n    this._click_endpoint_send = this._click_endpoint_send.bind(this)\n    this._input_endpoint_url_code = this._input_endpoint_url_code.bind(this)\n    this.comp = {\n      token: {\n        value: document.querySelector(\"#query-api-token-value\"),\n        copy_link: document.querySelector(\"#query-api-token-copy-link\"),\n      },\n      endpoints: document.querySelector(\"#query-api-endpoints\"),\n    }\n    this.desc_paths = {\n      list: {\n        name: \"Todas las consultas\",\n        description: \"Retorna los datos generales de todas las consultas creadas por el usuario.\",\n      },\n      results: {\n        name: \"Resultados de una consulta\",\n        description: \"Retorna los resultados de una consulta creada por el usuario.\"\n      },\n      geojson: {\n        name: \"Resultados de una consulta en GeoJSON\",\n        description: \"Retorna los resultados de una consulta en GeoJSON\"\n      }\n    }\n  }\n  show_view(on_history) {\n    this.comp.endpoints.innerHTML = \"\"\n    fetch (`${this.manager.url_base}api_config/`, {\n      method: \"GET\",\n      headers: {\"Content-Type\": \"application/json\"},\n      credentials: \"same-origin\"\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          this.api_config = data\n          this._set_in_view()\n          if (on_history) {\n            this.manager.engine._set_url_params(\"query-api\", null)\n          }\n        })\n      } else {\n        console.log(response)\n      }\n    })\n  }\n  _set_in_view() {\n    this.manager._build_sidebar()\n    this._set_token_control()\n    this._set_endpoints()\n    this.manager.engine._hide_all_views()\n    this.manager.engine.views.query_api.classList.remove(\"hidden\")\n  }\n\n  _set_token_control () {\n    this.comp.token.value.innerText = this.api_config.token\n    this.comp.token.copy_link.addEventListener(\n      \"click\", this._click_copy_link, false\n    )\n  }\n\n  _set_endpoints () {\n    for (let path in this.api_config.paths) {\n      let container = this._get_endpoint_container_element(path)\n      this.comp.endpoints.appendChild(container)\n      this._set_endpoint_events(container, path)\n    }\n  }\n\n  _get_endpoint_container_element (path) {\n    let container = document.createElement(\"div\")\n    container.classList.add(\"query-api-endpoint\")\n    container.setAttribute(\"id\", `query-api-endpoint-${path}`)\n    container.setAttribute(\"path\", path)\n    let curl = this._get_curl_example(path)\n    container.innerHTML = `\n      <div class=\"endpoint-name\">${this.desc_paths[path].name}</div>\n      <div class=\"endpoint-description\">${this.desc_paths[path].description}</div>\n      <div class=\"endpoint-controls\">\n        <div class=\"endpoint-params hidden\"></div>\n        <div class=\"endpoint-buttons\">\n          <div class=\"endpoint-clear secondary-button\">Limpiar</div>\n          <div class=\"endpoint-send primary-button\">Enviar</div>\n        </div>\n      </div>\n      <div class=\"endpoint-curl-preview\">\n        <div class=\"endpoint-curl-desc\">Ejemplo con curl</div>\n        <div class=\"endpoint-curl-value\" id=\"endpoint-${path}-curl-value\">${curl}</div>\n        <div class=\"endpoint-curl-copy copy-link-container\">\n          <div class=\"secondary-button\"\n             value=\"endpoint-${path}-curl-value\">Copiar\n          </div>\n        </div>\n      </div>\n      <div class=\"endpoint-response\">\n        <div class=\"endpoint-response-desc\">Respuesta</div>\n        <textarea class=\"endpoint-response-value\"></textarea>\n      </div>\n    `\n    return container\n  }\n\n  _set_endpoint_events (container, path) {\n    if ([\"results\", \"geojson\"].includes(path)) {\n      let params_container = container.querySelector(\".endpoint-params\")\n      params_container.innerHTML = `\n        <div class=\"param-url-code\">\n          <div class=\"param-url-code-desc\">Código URL</div>\n          <input class=\"param-url-code-input\" type=\"text\">\n        </div>\n      `\n      params_container.classList.remove(\"hidden\")\n      let input = params_container.querySelector(\".param-url-code-input\")\n      input.addEventListener(\"input\", this._input_endpoint_url_code, false)\n    }\n    let send = container.querySelector(\".endpoint-send\")\n    send.addEventListener(\"click\", this._click_endpoint_send, false)\n    let copy = container.querySelector(\".endpoint-curl-copy\")\n    copy.addEventListener(\"click\", this._click_copy_link, false)\n    let clear = container.querySelector(\".endpoint-clear\")\n    clear.addEventListener(\"click\", this._click_clear_endpoint_response, false)\n  }\n\n  _input_endpoint_url_code (event) {\n    let container = event.target.closest(\".query-api-endpoint\")\n    let path = container.getAttribute(\"path\")\n    let curl = this._get_curl_example(path, event.target.value)\n    container.querySelector(\".endpoint-curl-value\").innerText = curl\n  }\n\n  _click_clear_endpoint_response (event) {\n    let container = event.target.closest(\".query-api-endpoint\")\n    let response_value = container.querySelector(\".endpoint-response-value\")\n    response_value.value = \"\"\n    response_value.removeAttribute(\"rows\")\n  }\n\n  _click_endpoint_send (event) {\n    let container = event.target.closest(\".query-api-endpoint\")\n    let response_value = container.querySelector(\".endpoint-response-value\")\n    event.target.classList.add(\"disabled\")\n    response_value.value = \"Cargando...\"\n    let path = container.getAttribute(\"path\")\n    let url_code_input = container.querySelector(\".param-url-code-input\")\n    let url_code = url_code_input ? url_code_input.value: null\n    let url = this._get_full_path(path, url_code)\n    fetch (url, {\n      method: \"GET\",\n      headers: {\n        \"Content-Type\": \"application/json\",\n        \"Authorization\": `Token ${this.api_config.token}`\n      },\n    })\n    .then(response=> {\n      if (response.ok) {\n        response.json()\n        .then((data)=> {\n          response_value.value = JSON.stringify(data, null, \"\\t\")\n          response_value.setAttribute(\"rows\", \"20\")\n          event.target.classList.remove(\"disabled\")\n        })\n      } else if (response.status == 404){\n        response_value.value = \"No encontrado, verifique el código URL (url_code) de la consulta.\"\n        event.target.classList.remove(\"disabled\")\n      } else {\n        console.log(response)\n      }\n    })\n  }\n\n  _get_full_path (path, url_code) {\n    let full_path = this.api_config.paths[path]\n    if ([\"results\", \"geojson\"].includes(path)) {\n      let code = url_code ? url_code: \"[url_code]\"\n      full_path = full_path.replace(\"--url_code--\", code)\n    }\n    return full_path\n  }\n\n  _get_curl_example (path, url_code) {\n    let full_path = this._get_full_path(path, url_code)\n    return `curl -X GET ${this.api_config.host}${full_path} -H 'Authorization: Token ${this.api_config.token}'`\n  }\n\n  _click_copy_link (event) {\n    let value_element_id = event.target.getAttribute(\"value\")\n    let value = document.querySelector(`#${value_element_id}`).innerText\n    navigator.clipboard.writeText(value)\n    let container = event.target.closest(\".copy-link-container\")\n    if (!container.querySelector(\".action-success\")) {\n      let success = document.createElement(\"div\")\n      success.classList.add(\"action-success\")\n      success.innerHTML = \"<i class='icon ok-simple'></i> Copiado\"\n      container.appendChild(success)\n      setTimeout(function () {\n        container.querySelector(\".action-success\").remove()\n      }, 3000)\n    }\n  }\n}\n\nexport {\n  QueryAPIManager\n}\n","import {QueryListManager} from \"./list.js\"\nimport {QueryDetailManager} from \"./detail.js\"\nimport {QueryCreateManager, QueryUpdateManager} from \"./edit.js\"\nimport {QueryResultManager} from \"./results.js\"\nimport {QueryShareManager} from \"./share.js\"\nimport {QueryAPIManager} from \"./api.js\"\n\n\nclass QueryManager {\n  constructor({engine = null, url_base = \"\"}) {\n    this.letters = \"ABCDEFGHIJKLMNOPQRSTUXYZ\"\n    this.engine = engine\n    this.url_base = url_base\n    this.list = new QueryListManager({manager:this})\n    this.detail = new QueryDetailManager({manager:this})\n    this.create = new QueryCreateManager({manager:this})\n    this.update = new QueryUpdateManager({manager:this})\n    this.result = new QueryResultManager({manager:this, kind: \"result\"})\n    this.questions = new QueryResultManager({manager:this, kind: \"questions\"})\n    this.map = new QueryResultManager({manager:this, kind: \"map\"})\n    this.data = new QueryResultManager({manager:this, kind: \"data\"})\n    this.share = new QueryShareManager({manager: this})\n    this.api = new QueryAPIManager({manager: this})\n    this._click_go_to_view = this._click_go_to_view.bind(this)\n  }\n\n  _create_query_item(item, query_item) {\n    query_item.querySelector(\".name\").textContent = item.name\n    query_item.querySelector(\".total-responses .value\").textContent = item.total_responses\n    if (!item.start_at && !item.end_at) {\n      query_item.querySelector(\".times\").classList.add(\"hidden\")\n    } else {\n      this._set_times(item, query_item)\n    }\n    let status_value = query_item.querySelector(\".status > .status-value\")\n    status_value.classList.remove(\"draft\", \"finished\", \"active\", \"earring\")\n    status_value.textContent = item.status_verbose.label\n    status_value.classList.add(item.status_verbose.code)\n    return query_item\n  }\n\n  _get_question_kind_html (question_data) {\n    let html_text = \"\"\n    if (question_data.kind === \"TEXT\") {\n      let type = question_data.text_max_length > 150 ? \"largo\": \"corto\"\n      html_text += `<div class=\"query-question-kind-text\">Respuesta de texto ${type} (${question_data.text_max_length} caracteres)</div>`\n    } else if (question_data.kind === \"IMAGE\") {\n      html_text += `<div class=\"query-question-kind-image\">Respuesta de imagen o foto</div>`\n    } else if (question_data.kind === \"POINT\") {\n      html_text += `<div class=\"query-map-pointer\" id=\"map-pointer-${question_data.uuid}\"></div>`\n    }\n    return html_text\n  }\n\n  _set_times(item, query_item) {\n    query_item.querySelector(\".times\").classList.remove(\"hidden\")\n    if (item.start_at) {\n      let start_at = new Date(item.start_at).toLocaleString().split(\",\")[0]\n      query_item.querySelector(\".start-at\").classList.remove(\"hidden\")\n      query_item.querySelector(\".start-at\").textContent = `Desde: ${start_at}`\n    } else {\n      query_item.querySelector(\".start-at\").classList.add(\"hidden\")\n    }\n    if (item.end_at) {\n      query_item.querySelector(\".end-at\").classList.remove(\"hidden\")\n      let end_at = new Date(item.end_at).toLocaleString().split(\",\")[0]\n      query_item.querySelector(\".end-at\").textContent = `Hasta: ${end_at}`\n    } else {\n      query_item.querySelector(\".end-at\").classList.add(\"hidden\")\n    }\n  }\n\n  _build_sidebar () {\n    let current = this.engine.cursor.focus\n    let views_with_sidebar = [\"query-detail\", \"query-update\", \"query-share\"]\n    let result_views = [\"query-result\", \"query-data\", \"query-map\", \"query-questions\"]\n    let admin_content = document.querySelector(\".admin-content\")\n    let sidebar = document.querySelector(\".admin-content > .sidebar\")\n    if (!sidebar) {\n      sidebar = document.createElement(\"div\")\n      sidebar.classList.add(\"sidebar\")\n      admin_content.prepend(sidebar)\n    } else {\n      sidebar.innerHTML = \"\"\n    }\n    if ([...result_views, ...views_with_sidebar].includes(current)) {\n      sidebar.innerHTML = `\n        <div class=\"sidebar-element${current == 'query-detail'?' current': ''}\" to=\"query-detail\">\n          Ver consulta\n        </div>\n        <div class=\"sidebar-element${result_views.includes(current)?' current': ''}\" to=\"query-result\">\n          Resultados\n        </div>\n        <div class=\"sidebar-element${current == 'query-share'?' current': ''}\" to=\"query-share\">\n          Compartir\n        </div>\n        <div class=\"sidebar-element${current == 'query-update'?' current': ''}\" to=\"query-update\">\n          Editar\n        </div>\n      `\n      for (let element of sidebar.querySelectorAll(\".sidebar-element\")) {\n        element.addEventListener(\"click\", this._click_go_to_view, false)\n      }\n    } else if (current == \"query-create\") {\n      sidebar.innerHTML = `\n        <div class=\"sidebar-element current\" to=\"query-create\">\n          Crear consulta\n        </div>\n      `\n    } else {\n      sidebar.remove()\n    }\n  }\n\n  _click_go_to_view(event) {\n    let view = event.target.getAttribute(\"to\")\n    if (view != this.engine.cursor.focus) {\n      this.engine.show_view(view, true)\n    }\n  }\n\n  get_kind_label(question_data) {\n    let kind_label = \"\"\n    if (question_data.kind === \"TEXT\" && question_data.text_max_length > 150) {\n      kind_label = \"Texto largo\"\n    } else if (question_data.kind === \"TEXT\" && question_data.text_max_length <= 150) {\n      kind_label = \"Texto corto\"\n    } else if (question_data.kind === \"SELECT\") {\n      kind_label = \"Selección múltiple\"\n    } else if (question_data.kind === \"SELECT_IMAGE\") {\n      kind_label = \"Selección múltiple e imágenes\"\n    } else if (question_data.kind === \"IMAGE\") {\n      kind_label = \"Imagen\"\n    } else if (question_data.kind === \"POINT\") {\n      kind_label = \"Ubicación\"\n    }\n    return kind_label\n  }\n\n}\n\nexport {\n  QueryManager\n}\n","import {\n  QueryManager\n} from \"./queries/manager.js\"\n\n\n\nclass AdminEngine {\n  constructor (\n    { url_base = \"\" , csrf_token = \"\", focus = null, key = null, user = null}\n  ) {\n    this.user = user\n    this.csrf_token = csrf_token\n    this.cursor = {focus: focus?focus:\"query-list\", key}\n    this.url_base = url_base\n    this.ready = this.ready.bind(this)\n    this._onpopstate = this._onpopstate.bind(this)\n    this.blocked = false\n    this.blocked_to = null\n    document.addEventListener(\"DOMContentLoaded\", this.ready)\n    this.view_names = [\n      \"loading\",\n      \"query_list\",\n      \"query_detail\",\n      \"query_create\",\n      \"query_update\",\n      \"query_result\",\n      \"query_questions\",\n      \"query_map\",\n      \"query_data\",\n      \"query_share\",\n      \"query_api\",\n    ]\n    this.views = {}\n    this._general_click = this._general_click.bind(this)\n    this._click_confirm_blocked_to = this._click_confirm_blocked_to.bind(this)\n    document.querySelector(\"body > .main-container\").addEventListener(\"click\", this._general_click, false)\n  }\n\n  ready() {\n    this.query_manager = new QueryManager({engine: this, url_base: this.url_base})\n    window.addEventListener(\"popstate\", this._onpopstate, false)\n    this._set_admin_menu()\n    this._set_views()\n    this._set_modal()\n    this.show_view(this.cursor.focus, true)\n  }\n\n  _general_click (event) {\n    let dropdown_class = \"dropdown-wrapper\"\n    let current_wrapper = event.target.classList.contains(dropdown_class)? event.target : event.target.closest(`.${dropdown_class}`)\n    for (let wrapper of document.querySelectorAll(`.${dropdown_class}`)) {\n      if (wrapper !== current_wrapper) {\n        wrapper.querySelector(\".dd-content\").classList.add(\"hidden\")\n      }\n    }\n  }\n\n  _onpopstate (event) {\n    let query_params = new URLSearchParams(window.location.search)\n    this.cursor = event.state\n    this.show_view(this.cursor.focus, false)\n  }\n\n  _click_menu_item(event) {\n    let focus = event.target.focus\n    this.show_view(focus, true)\n    event.target.closest(\".menu-content\").classList.add(\"hidden\")\n  }\n\n  _set_admin_menu() {\n    this._click_menu_item = this._click_menu_item.bind(this)\n    let menu_button = document.querySelector(\"#menu-button\")\n    let menu_content = document.querySelector(\"#menu-content\")\n    menu_button.addEventListener(\"click\", (event) => {\n      if (menu_content.classList.contains(\"hidden\")) {\n        menu_content.classList.remove(\"hidden\")\n      } else {\n        menu_content.classList.add(\"hidden\")\n      }\n    })\n    this._set_admin_menu_item(\"query-create-link\", \"query-create\", menu_content)\n    this._set_admin_menu_item(\"query-list-link\", \"query-list\", menu_content)\n    this._set_admin_menu_item(\"query-api-link\", \"query-api\", menu_content)\n  }\n\n  _set_admin_menu_item(id, focus, menu_content) {\n    let menu_item = menu_content.querySelector(`#${id}`)\n    menu_item.focus = focus\n    for (let child of menu_item.children) {\n      child.focus = focus\n    }\n    menu_item.addEventListener(\"click\", this._click_menu_item, false)\n  }\n\n  _set_views () {\n    for (let name of this.view_names) {\n      let view = document.querySelector(`#${name.replace(\"_\", \"-\")}`)\n      this.views[name] = view\n    }\n  }\n\n  _set_modal() {\n    this._click_out_modal_content = this._click_out_modal_content.bind(this)\n    let modal = document.querySelector(\"#admin-modal\")\n    modal.addEventListener(\"click\", this._click_out_modal_content, false)\n  }\n\n  _click_out_modal_content(event) {\n    if ([\"admin-modal\", \"admin-modal-close\"].includes(event.target.getAttribute(\"id\"))) {\n      this.hide_modal()\n    }\n  }\n\n  _hide_all_views () {\n    for (let name in this.views) {\n      this.views[name].classList.add(\"hidden\")\n    }\n  }\n\n  _set_loading () {\n    this._hide_all_views()\n    this.views.loading.classList.remove(\"hidden\")\n  }\n\n  show_view(name, on_history) {\n    if (this.blocked === true) {\n      this.blocked_to = {name, on_history}\n      let config = {\n        class: \"blocket-to-confirmation\",\n        icon: \"alert\",\n        title: \"¿Estás seguro que quieres salir sin guardar ?\",\n        content: \"\",\n        actions: [\n          {name: \"Sí\", click: this._click_confirm_blocked_to},\n          {name: \"No\", click: this.hide_modal},\n        ],\n      }\n      this.show_modal(config)\n      return\n    }\n    this._set_loading()\n    this.cursor.focus = name\n    let manager = this._get_view_manager(name)\n    if (manager && manager.show_view) {\n      manager.show_view(on_history)\n    } else {\n      this.cursor.focus = \"query-list\"\n      this.query_manager.list.show_view(on_history)\n    }\n  }\n\n  _click_confirm_blocked_to(event) {\n    this.blocked = false\n    this.hide_modal()\n    this.show_view(this.blocked_to.name, this.blocked_to.on_history)\n    this.blocked_to = null\n  }\n\n  _get_view_manager(name) {\n    let view_name = name.split(\"-\")\n    let view_kind = view_name[0]\n    let view_selector = view_name[1]\n    let manager = null\n    if (view_kind === \"query\") {\n      manager = this.query_manager[view_selector]\n    }\n    return manager\n  }\n\n  _set_url_params(focus, key) {\n    let query_params = new URLSearchParams(window.location.search)\n    query_params.set(\"f\", focus)\n    this.cursor.focus = focus\n    if (key) {\n      query_params.set(\"k\", key)\n      this.cursor.key = key\n    } else {\n      query_params.delete(\"k\")\n      this.cursor.key = null\n    }\n    if (focus !== \"query-map\") {\n      query_params.delete(\"r\")\n    }\n    history.pushState(this.cursor, null, \"?\" + query_params.toString())\n  }\n\n  show_modal(config) {\n    let modal = document.querySelector(\"#admin-modal\")\n    modal.config = config\n    let html_element = null\n    if (config.html_element) {\n      html_element = config.html_element\n    }\n    else {\n      html_element = document.createElement(\"div\")\n      html_element.innerHTML = `\n        <div class=\"modal-icon-${config.icon}\"></div>\n        <div class=\"modal-title\">${config.title}</div>\n        <div class=\"modal-content\">${config.content}</div>\n        <div class=\"modal-actions\"></div>\n      `\n      let actions = html_element.querySelector(\".modal-actions\")\n      for (let action of config.actions) {\n        let button = document.createElement(\"div\")\n        button.classList.add(\"primary-button\")\n        button.innerText = action.name\n        button.addEventListener(\"click\", action.click, false)\n        actions.appendChild(button)\n      }\n    }\n    html_element.classList.add(config.class)\n    modal.querySelector(\".admin-modal-content\").appendChild(html_element)\n    modal.classList.remove(\"hidden\")\n  }\n\n  hide_modal() {\n    let modal = document.querySelector(\"#admin-modal\")\n    modal.classList.add(\"hidden\")\n    modal.querySelector(`.${modal.config.class}`).remove()\n  }\n\n  set_navbar_message(message, timeout) {\n    let container = document.querySelector(\".navbar .navbar-message-container\")\n    container.querySelector(\".navbar-message-text\").innerText = message\n    if (timeout) {\n      container.classList.remove(\"hidden\")\n      setTimeout(function() {\n        container.classList.add(\"hidden\")\n      }, timeout);\n    }\n  }\n}\n\nexport {AdminEngine}\n"],"names":["QueryListManager","constructor","manager","data","_click_query_detail","bind","_click_query_create","_click_status_dropdown","_click_status_filter","_change_search_input","filters","search","status","comps","button","document","querySelector","content","items","querySelectorAll","query_list","query_template","query_create","action","addEventListener","item","show_view","on_history","fetch","url_base","method","headers","credentials","then","response","ok","json","list","_set_in_view","engine","_set_url_params","console","log","length","classList","add","_set_query_list","innerHTML","remove","_build_sidebar","_hide_all_views","views","template","cloneNode","_is_query_in_the_filter","query_item","returned_query_item","_create_query_item","detail_link","query_uuid","uuid","user","is_superuser","created_by_email","email","createElement","textContent","appendChild","query","lower_search","toLowerCase","search_in_name","name","includes","equal_status","status_verbose","code","event","cursor","key","currentTarget","contains","target","status_code","getAttribute","value","trim","QueryDetailManager","charts","summary","map_pointers","_click_query_edit","url_code","is_active","is_earring","setAttribute","links","submit","_set_query_preview","query_detail","description_element","description","questions","i","index","answer_result","answer_results","question","question_container","get_kind_label","image","kind","options_container","option_index","option","options","inner_html","letters","_get_question_kind_html","default_point","latitude","longitude","zoom","default_zoom","latlng","L","latLng","map","setView","tileLayer","maxZoom","zoomControl","addTo","attributionControl","setPrefix","dragging","disable","doubleClickZoom","scrollWheelZoom","setTimeout","window","dispatchEvent","Event","push","QueryEditBase","required_fields","_get_default_data","question_images","question_option_images","inputs","errors","buttons","can_edit_questions","_click_publish","_dropdown_create_question","_click_create_question","_move_question_ondragstart","_move_question_ondragend","_move_question_ondrop","_click_remove_question","_change_input","_click_question_add_option","_click_question_max_answers_menu","_click_question_max_answers_set","_click_question_remove_option","_click_question_image_modal","_click_question_image_rm","_click_question_option_image","_change_map_pointer","_change_input_question_image","_set_initial","_set_publish_button","_set_create_question_button","_set_query_inputs","start_at","end_at","active","auth_rut","auth_email","publish","view_type","disabled","_set_loading","execute_service","_clean_data","_remove_all_question_option_image","_build_question_from_data","field","input","Date","toISOString","split","parentNode","dataset","replicatedValue","validate_inputs","error_containers","container","_set_errors_message","innerText","question_field","times","parseInt","checked","no_question_message","_val_field_value_is_required","order","_val_question_options","_val_date_field_value","new_question","max_question_message","Object","keys","message","_set_field_error","_clean_field_error","question_index","option_values","isNaN","kinds","Array","from","type","dropdown","required","text_max_length","scrollIntoView","questions_container","question_data","_create_question_element","_set_question_image","delete_button","_prepare_question_inputs","_set_map_pointer","click_delete","_get_question_delete_callback","_set_question_draggable","_set_question_error_containers","_set_disable_edit_questions","setPosition","center","getCenter","lat","lng","getZoom","_get_question_id","question_id","kind_label","question_content","_set_question_options","_set_question_max_answers","draggable","actions","action_image","question_image_input","insertBefore","firstChild","image_preview","image_preview_content","url","rm_button","html_element","config","class","image_input","show_modal","question_uuid","file","files","reducer","ImageBlobReduce","pica","features","toBlob","max","blob","URL","createObjectURL","reduced_file","File","lastModified","getTime","data_transfer","DataTransfer","question_image","hide_modal","catch","error","fields","element","node","placeholder","closest","splice","question_add_button","option_list","option_data","option_id","_set_question_option_image","question_option_image","_get_question_option_image","cropper","destroy","_remove_question_option_image","image_widget","input_id","image_element","cropper_data","getData","Cropper","aspectRatio","viewMode","movable","zoomable","rotatable","scalable","_set_internal_question_option_image","founded_index","index_for_remove","question_item","option_item","max_answers","empty_option","button_label","ondragstart","ondragend","move_previous","move_next","ondragenter","ondragleave","ondragover","preventDefault","ondrop","cu